INSERT INTO daily_questions (id, interest_id, question_text, question_level, empathy_guide, hint_guide, leading_question_guide)
VALUES
  (301, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '최근에 꼭 필요하지 않지만 산 물건은 무멋인가요?', 3, '필요하진 않지만 꼭 사고 싶은 물건들이 있어요.', '내 마음에 드는 것만으로도 존재가치가 충분한 물건들을 생각해보세요.', '왜 꼭 사야하진 않지만 구매까지 하게 된 이유도 생각해봐요.'),
  (302, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '평생 한 가지 음식만 먹어야 할 때 선택하고 싶은 음식은 무엇인가요?', 3, '매일 먹어도 질리지 않는 음식이 하나쯤 있어요.', '든든한 밥이나 면 요리 혹은 평소 가장 좋아하는 음식을 떠올려 보세요.', '그 음식을 먹을 때 왜 유독 마음이 편안해지나요?'),
  (303, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '야심 차게 시작했지만 딱 일주일 만에 포기한 취미는 무엇인가요?', 3, '도전했다는 것만으로도 충분히 재미있는 경험이에요.', '등록했지만 3일도 가지 못한 헬스장인가요? 아니면 야심차게 구독했지만 공부하지 않은 영어 회화인가요?', '왜 계속하지 못했을까요?'),
  (304, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '사진을 많이 찍나요 눈으로만 담는걸 즐기나요?', 3, '멋진 풍경을 마주했을 때 카메라를 먼저 꺼내는지, 혹은 가만히 감상부터 하는지 떠올려 봐요.', '기록과 현장감 중에서 무엇을 더 중요하게 생각하나요?', '사진 찍기에 집중하느라 순간을 놓쳤거나, 사진을 남기지 않아 아쉬웠던 경험이 있나요?'),
  (305, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '위시리스트에서 가장 사고 싶은 것은 뭔가요?', 3, '위시리스트가 가득 차도 그중에서 가장 생각나는 물건이 있죠.', '독특해서 매일 입기 어려울 것 같은 옷, 맛있어보이지만 비싼 젤리, 신기한데 쓸지 모를 물건인가요?', '왜 사고 싶었는데 아직 사지 않았는지 떠올려봐요.'),
  (306, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '최근 산 것 중 가장 만족스러운 건 뭔가요?', 3, '돈을 썼는데도 더 풍족해진 것 같은 소비가 있어요.', '왜 그 소비가 유독 뿌듯했나요?', '소비 이후로 뭐가 달라졌는지 떠올려봐요.'),
  (307, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '인생 드라마는 무엇인가요?', 3, '16부작이어도 너무 짧다고 느껴질 정도로 재밌었던 드라마를 떠올려봐요.', '로맨스, 스릴러, 코미디 혹은 직업물이었나요?', '그 드라마가 내게 미친 영향도 떠올려봐요.'),
  (308, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '쉴 때마다 구경하는 앱은 무엇인가요?', 3, '쉴 틈이 날 때마다 손이 가는 앱이 있죠.', '단순 시간 떼우기인가요 아니면 꽂혀서 계속 들어가게 되는 건가요?', '그 앱을 몇시간 썼는지도 확인해봐요.'),
  (309, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '나중에 살고 싶은 곳은 어디인가요?', 3, '맑은 공기가 있는 지방, 화려한 불빛으로 가득한 도시, 혹은 오래 살아 정감이 가는 고향인가요?', '언제 어떻게 살고 싶은지도 떠올려봐요.', '이상적인 집은 뭐라고 생각하고 있나요?'),
  (310, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '최애 잠옷은 무엇인가요?', 3, '너덜너덜해져도 놓아줄 수 없는 최애 잠옷이 있나요?', '왜 그 잠옷을 좋아하는지도 궁금해요.', '집에서 어떻게 지내는 걸 좋아하나요?'),
  (311, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '취미활동으로 일주일에 어느정도의 시간을 들이나요?', 3, '좋아하는 일이어도 매일 같이 시간을 내기 어렵기도 해요.', '취미 생활은 무엇인지, 어떻게 즐기고 있는지 떠올려봐요.', '취미에 대한 목표는 무엇인가요?'),
  (312, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '낮잠 자는 걸 좋아하나요?', 3, '사람마다 수면 방식이 달라요.', '밤에 짧게 자고 낮잠 자는 걸 즐기기도, 낮잠 자는 걸 기피하기도 하죠.', '언제쯤 졸음이 쏟아졌는지도 떠올려봐요.'),
  (313, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '버스와 지하철 중 어떤 걸 더 좋아하나요?', 3, '버스를 타면서 풍경을 즐기기도 하고', '지하철을 타며 예측할 수 있는 이동하는 것을 선호하기도 해요.', '어떤 걸 더 선호하고 그 이유는 무엇인지 들려주세요.'),
  (314, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '여행 갈 때 계획파인가요 무계획파인가요?', 3, '여행을 가는 건 즐거운 일이죠.', '더 즐기기 위해 촘촘한 계획을 채우기도 하고, 자유롭게 즐기고자 계획 없이 떠나기도 해요.', '같이 가는 사람에 따라 달라지는지, 어떤 여행을 즐기는지 떠올려봐요.'),
  (315, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '공부 스타일은 어떻게 되나요?', 3, '최대한 긴 시간을 공부에 쏟아붓는 공부법도 있고', '가장 집중이 잘되는 짧은 시간 동안 집중하는 방식으로 공부하는 방법도 있어요.', '어떤 공부법을 왜 선택하게 됐는지 생각해봐요.'),
  (316, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '가장 좋아하는 유튜버는 누구인가요?', 3, '유튜브가 레드오션이라고 해도 자꾸 생각나서 찾게 되는 유튜버가 있나요?', '어떻게 그 유튜버를 알게 됐는지 떠올려봐요.', '어떤 점이 자꾸 영상을 보게 만드나요?'),
  (317, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '노래방에 가면 꼭 부르는 노래는 무엇인가요?', 3, '고음이 가득해서 스트레스가 풀리는 노래, 서정적인 멜로디가 좋은 노래 혹은 친구들과 부르기 재밌는 아이돌 노래인가요?', '그 노래의 어떤 부분이 가장 좋은지 궁금해요.', '그리고 노래방을 어떻게 즐기는 걸 좋아하나요?'),
  (318, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '가장 좋아하는 게임은 무엇인가요?', 3, '스트레스를 받으면 자꾸 찾게 되는 게임이 있나요?', '그 게임을 왜 좋아하게 됐는지 생각해봐요.', '어떤 시간대에 그 게임을 하는지도 적어봐요.'),
  (319, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '반대되는 성격이 좋나요 아니면 비슷한 성격이 좋나요?', 3, '다른 성격이라 더 좋기도, 같은 성격이라 더 좋기도 해요.', '내가 좋아하는 유형의 사람들을 떠올리며 좋아하는 성격을 구체적으로 생각해봐요.', '왜 그런 성격을 선호하나요?'),
  (320, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '힘들 때마다 찾게 되는 곳이 있나요?', 3, '역사적 공간에서 바쁘게 움직이는 광화문, 바다가 보여서 위로가 되는 묵호 등 각자 다른 공간에서 위로를 얻곤 해요.', '왜 힘이 되는 공간이라고 생각하나요?', '그곳을 찾았던 기억들을 더듬어봐요.'),
  (321, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '한 번쯤은 시도해보고 싶은 패션 스타일이 있나요?', 3, '멋있다고 생각하면서 안 입는 스타일 있지 않나요?', '나랑 안 어울릴 것 같아서, 눈에 띌 것 같아서...', '왜 그 스타일을 입고 싶은지도 떠올려봐요.'),
  (322, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '좋아하는 계절과 시간대는 언제인가요?', 3, '그때 주로 어디에서 누구와 무엇을 하고 싶은지 상상해 보세요.', '그 풍경을 가만히 바라볼 때 내 마음은 어떤 상태가 되나요?', '그 계절과 시간이 돌아오면 나는 어떤 새로운 다짐을 하나요?'),
  (323, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '가장 좋아하는 브랜드는 무엇인가요?', 3, '그 브랜드의 물건을 처음 샀을 때나 매장을 방문했을 때의 설렘이 기억나나요?', '그 브랜드가 가진 분위기나 철학이 나의 어떤 점과 닮아 있다고 느끼나요?', '이 브랜드의 물건들이 내 일상에 어떤 작은 행복이나 자부심을 더해주나요?'),
  (324, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '지금 당장 떠나고 싶은 여행지는 어디인가요?', 3, '왜 하필 지금 그곳의 풍경이 간절하게 떠오르는지 생각해 보세요.', '그곳에 도착해서 가장 먼저 내뱉고 싶은 말은 무엇인가요?', '여행을 마치고 돌아올 때 어떤 마음을 챙겨오고 싶나요?'),
  (325, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '좋아하는 시의 제목이나 글귀가 있나요?', 3, '그 문장이 내 마음의 어느 부분을 정확히 건드렸나요?', '힘들 때마다 그 문장을 부적처럼 꺼내 보며 위로를 받나요?', '그 글귀를 쓴 작가와 대화한다면 어떤 질문을 던지고 싶나요?'),
  (326, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '평소 선호하는 화장 분위기는 무엇인가요?', 3, '화장을 마친 거울 속의 나를 볼 때 어떤 기분이 드나요?', '내가 타인에게 보여주고 싶은 ''나의 이미지''는 무엇인가요?', '화장은 나를 숨기는 도구인가요, 아니면 드러내는 수단인가요?'),
  (327, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '좋아하는 외국어는 무엇인가요?', 3, '그 언어의 어떤 발음이나 뉘앙스가 특히 매력적인가요?', '그 언어를 사용하는 나라에 살고 있는 나를 상상해본 적 있나요?', '새로운 언어를 배울 때 내가 확장되는 기분을 느끼나요?'),
  (328, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '꾸준히 수집하는 물건이 있나요?', 3, '그 물건들을 모으게 된 첫 시작은 무엇이었는지 기억나나요?', '나열된 수집품들을 볼 때 어떤 정서적인 안정감을 느끼나요?', '이 물건들이 훗날 나에 대해 무엇을 말해줄 것 같나요?'),
  (329, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '하루만 다른 사람으로 살 수 있다면 어떤 사람으로 살고 싶나요?', 3, '딱 떠오르는 사람이 있나요? 연예인이든 가상인물이든 괜찮아요.', '그 사람의 뭐가 궁금하거나 부러운 건가요?', '지금의 나와 다른 점도 떠올려봐요.'),
  (330, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '돈 걱정 없이 한 달 살기 한다면 어디로 가고 싶나요?', 3, '유럽 소도시, 동남아 해변, 일본 시골... 어디가 떠오르나요?', '거기서 뭐 하면서 보내면 즐거울 것 같은지도 떠올려봐요.', '가고 싶다는 마음을 갖게 된 이유도 생각해봐요.'),
  (331, (SELECT id FROM interests WHERE code = 'PREFERENCE'), 'SNS에 일상을 올리는 편인가요?', 3, '가장 최근에 올린 sns 게시글은 뭔가요?', '자주 올리는 편인지도 궁금해요.', '공유하는 게 좋아요, 아니면 부담스러워요?'),
  (332, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '오늘 먹은 것 중 기분까지 완벽하게 충전해준 메뉴는?', 3, '한 입 먹는 순간 "행복해!"라고 외치게 된 음식이 있나요?', '맛뿐만 아니라 함께한 사람이나 장소의 분위기는 어땠나요?', '이 메뉴를 생각하면 떠오르는 기분 좋은 에너지를 적어봐요.'),
  (333, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '오늘 나의 오감을 자극한 인상 깊은 소리나 향기는 무엇인가요?', 3, '길 가다 들은 노래, 혹은 코끝을 스친 계절의 냄새는?', '그 감각이 나의 무의식 속에 잠들어 있던 어떤 기억을 깨웠나요?', '감각을 통해 하루를 더 풍성하게 느꼈던 순간을 기록하세요.'),
  (334, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '이번 주 나의 관심을 독차지한 뜨거운 키워드는 뭐였나요?', 3, '요즘 유독 눈길이 가고 더 알고 싶어지는 분야가 있나요?', '그 관심사가 나를 설레게 하는 이유는 무엇인가요?', '그 열정을 더 깊게 파고들기 위해 내가 할 수 있는 즐거운 일은 무엇일까요?'),
  (335, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '오늘 쓴 돈이나 시간 중 가심비 최고였던 건 무엇이었나요?', 3, '소비나 시간 활용 중 마음을 가장 풍요롭게 한 건 무엇인가요?', '만족감의 근원이 실용성이었나요, 아니면 나를 위한 선물이었나요?', '이런 만족을 더 자주 누리기 위해 나에게 필요한 투자는 뭘까?'),
  (336, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '오늘 내 복잡한 마음을 잠시 쉬게 해준 건 무엇이었나요?', 3, '생각을 멈추고 온전히 몰입하거나 쉴 수 있었던 활동은?', '그 활동이 왜 나에게 그토록 큰 평온함을 주었을까요?', '내일도 그 평온한 시간을 나에게 선물할 수 있을까요?'),
  (337, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '오늘 나답게 쉬는 법을 아주 멋지게 실천했나요?', 3, '남들이 하는 휴식 말고, 나만이 아는 진정한 쉼의 방식은?', '그 쉼이 나의 컨디션을 회복시키는 데 얼마나 효과적이었나요?', '"나답게 쉰다는 것"을 정의하는 나만의 문장을 만들어봐요.'),
  (338, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '오늘 새롭게 접한 정보 중 나의 호기심을 깨운 건 무엇이었나요?', 3, '처음 알게 된 지식이나 나를 놀라게 한 새로운 관점은?', '그 정보가 나의 생각이나 행동에 어떤 신선한 바람을 일으켰나요?', '잊지 않도록 나만의 한 줄 지식 노트를 남겨보세요.'),
  (339, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '유튜버가 된다면 어떤 콘텐츠를 올리고 싶나요?', 3, '조회수와 상관없이 내가 가장 즐겁게 이야기할 수 있는 주제는 무엇인가요?', '그 콘텐츠를 통해 사람들에게 어떤 정보나 감동을 전달하고 싶나요?', '영상 속의 내 모습이 현실의 나와 얼마나 닮아 있기를 바라나요?'),
  (340, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '집에 방이 하나 더 생긴다면 무엇을 하는 장소로 만들고 싶나요?', 3, '그 공간은 나를 위한 완벽한 쉼터인가요, 아니면 무언가에 몰입하는 공간인가요?', '그 방에 혼자 있을 때 어떤 소품이나 가구가 나를 가장 편안하게 만들까요?', '현실의 방에서 구현하지 못한 나의 어떤 꿈이 그 새로운 방에 투영되어 있나요?'),
  (341, (SELECT id FROM interests WHERE code = 'PREFERENCE'), '평소 어떤 상상을 가장 자주 하나요?', 3, '주로 현실에서 벗어나고 싶을 때인가요, 아니면 더 나은 미래를 꿈꿀 때인가요?', '상상 속의 시공간은 지금 내가 발을 딛고 있는 현실과 얼마나 다른가요?', '그 상상을 마치고 현실로 돌아올 때 나에게 어떤 감정적 변화가 생기나요?'),
  (342, (SELECT id FROM interests WHERE code = 'EMOTION'), '감정이 격해질 때 말이 많아지나요 적어지나요?', 3, '화가 나거나 슬펐던 최근의 순간을 떠올려 보세요.', '내 마음을 설명하려 애썼나요, 아니면 침묵하며 감정을 가라앉혔나요?', '감정이 격해졌을 때의 행동에 대해 후회한적이 있는지도 생각해봐요.'),
  (343, (SELECT id FROM interests WHERE code = 'EMOTION'), '내면의 감정과 타인이 인식하는 감정의 강도는 얼마나 다른가요?', 3, '나는 격렬했지만 타인은 무덤덤했던 순간, 혹은 내 작은 감정이 타인에게 과하게 전달되었던 기억을 떠올려 보세요.', '감정을 의도적으로 숨겨서 무덤덤해 보이나요, 아니면 더 잘 전달하기 위해 실제보다 강하게 표현하나요?', '타인이 내 감정을 실제보다 과하게 혹은 부족하게 읽을 때, 안도감을 느끼나요 아니면 섭섭함을 느끼나요?'),
  (344, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 갑자기 멍해진 순간이 있었나요?', 3, '잠깐 세상의 소음이 차단된 듯한 때가 있었나요?', '그때 머릿속을 스친 아주 찰나의 생각은 무엇이었나요?', '그 멍함이 나에게 휴식을 권한 건 아니었을까요?'),
  (345, (SELECT id FROM interests WHERE code = 'EMOTION'), '최근 나에게 고생했다고 토닥여주고 싶은 날은 언제였나요?', 3, '버겁지만 꾹 참고 끝까지 해냈던 장면이 떠오르나요?', '그때 나를 버티게 했던 마음의 힘은 무엇이었을까요?', '그날의 나에게 지금 건네고 싶은 위로 한마디는 뭐였나요?'),
  (346, (SELECT id FROM interests WHERE code = 'EMOTION'), '지금 내 머릿속에 흐르는 BGM은 무엇인가요?', 3, '지금 기분에 어울리는 멜로디나 가사가 떠오르나요?', '가사가 내 마음 같아서인가요, 아니면 분위기 때문인가요?', '그 노래가 지금 나에게 들려주고 싶은 말은 무엇일까요?'),
  (347, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 속으로 나를 가만히 안아준 적이 있나요?', 3, '"괜찮아"라고 스스로에게 작게 속삭인 순간이 있나요?', '그때 필요했던 건 따뜻한 위로였나요, 아니면 잠깐의 쉼이었나요?', '그 셀프 토닥임 이후로 남은 하루가 어떻게 달라졌나요?'),
  (348, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 하루를 관통한 감정에 이름을 붙인다면 무엇일까요?', 3, '오늘 하루 종일 내 곁을 지켰던 기분은 무엇인가요?', '그 감정이 시작된 첫 번째 단추를 찾아볼까요?', '1~10점 사이라면 몇 점인가요? 그 점수의 이유는요?'),
  (349, (SELECT id FROM interests WHERE code = 'EMOTION'), '울컥하거나 감정이 터질 뻔한 순간, 어떻게 넘겼나요?', 3, '감정이 파도처럼 밀려왔을 때 나는 어떤 행동을 했나요?', '솔직하게 표현했나요, 아니면 꾹꾹 눌러 담았나요?', '다음에 비슷한 파도가 오면 어떻게 맞이하고 싶나요?'),
  (350, (SELECT id FROM interests WHERE code = 'EMOTION'), '몸과 마음이 기분 좋게 늘어진 순간이 있었나요?', 3, '긴장이 탁 풀리면서 나른해졌던 때가 언제였나요?', '문제가 해결돼서인가요, 아니면 그냥 내려놓기로 했나요?', '이런 편안함을 더 자주 느끼려면 무엇이 필요할까요?'),
  (351, (SELECT id FROM interests WHERE code = 'EMOTION'), '내 안에서 낯선 감정이 고개를 들었던 적이 있나요?', 3, '평소의 나답지 않은 반응이나 감정이 올라왔었나요?', '그 감정이 평소의 나와 어떻게 달랐는지 살펴보세요.', '새롭게 발견한 그 마음에게 어떤 이름을 붙여줄까요?'),
  (352, (SELECT id FROM interests WHERE code = 'EMOTION'), '나를 가장 잘 설명해주는 노래 한 소절이 있나요?', 3, '들을 때마다 "이건 내 얘기야" 싶은 가사가 있나요?', '그 가사가 나의 어떤 기억이나 상처를 건드리나요?', '지금 이 순간의 나에게 그 가사는 어떤 의미인가요?'),
  (353, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 내 자신에게 칭찬 한 마디를 남긴다면 무엇일까요?', 3, '아주 사소해도 괜찮아요. 뿌듯했던 순간이 있었나요?', '그때의 나는 어떤 마음으로 그 일을 해냈나요?', '나 자신에게 건네는 짧고 강렬한 칭찬 한 문장을 적어봐요.'),
  (354, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 하루 감정 그래프를 그리면 어떤 모양일까요?', 3, '잔잔한 호수 같았나요, 아니면 롤러코스터 같았나요?', '그래프가 가장 높이 솟았거나 푹 꺼졌던 지점엔 뭐가 있었나요?', '이 흐름을 아는 것만으로도 나를 이해하는 큰 단서가 돼요.'),
  (355, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 감정을 억누르기 힘든 순간이 있었나요?', 3, '참으려 했지만 결국 툭 튀어나온 감정이 있나요?', '그 폭발의 방아쇠를 당긴 상황이나 사람이 누구였나요?', '참지 못한 게 잘못은 아니에요. 그 감정이 외친 진심은 뭘까요?'),
  (356, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 아주 잠깐이라도 행복이 스친 순간이 있나요?', 3, '거창하지 않아도 돼요. 입가에 미소가 번진 찰나가 있나요?', '그 행복은 관계에서 왔나요, 성취에서 왔나요?', '나를 행복하게 만드는 필승 공식을 하나 찾아볼까요?'),
  (357, (SELECT id FROM interests WHERE code = 'EMOTION'), '축 처져 있다가 기분이 다시 살아난 계기가 있나요?', 3, '무거웠던 기분이 가벼워졌던 그 전환점이 궁금해요.', '외부의 자극 때문이었나요, 내 안에서 바뀐 생각 때문인가요?', '나만의 ''기분 전환 치트키''를 하나 저장해둘까요?'),
  (358, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 내 마음이 회색빛처럼 흐릿했던 때가 있나요?', 3, '아무런 감흥도 없고 무뎌졌던 순간이 있었나요?', '그 무딤이 너무 지쳐서일까요, 나를 지키려는 방어였을까요?', '감정도 쉼이 필요해요. 그 상태의 나에게 어떤 말을 해줄까요?'),
  (359, (SELECT id FROM interests WHERE code = 'EMOTION'), '요즘 나를 든든하게 지탱해주는 감정은 무엇인가요?', 3, '내 안에서 뿌리 깊게 자리 잡은 긍정적인 힘이 있나요?', '그 에너지는 어디서 공급받고, 어떻게 유지되고 있나요?', '나를 버티게 해주는 그 고마운 마음에게 인사해봐요.'),
  (360, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 하루 중 가장 단골손님처럼 찾아온 감정은?', 3, '자꾸만 반복해서 느껴졌던 기분이 무엇이었나요?', '특정 상황에서만 그랬나요, 아니면 배경지처럼 깔려 있었나요?', '그 감정이 나에게 하고 싶어 하는 말은 무엇일까요?'),
  (361, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 감정이 내 예상과 전혀 다르게 흘러갔나요?', 3, '"이 상황에선 이럴 줄 알았는데" 싶었던 의외의 감정은?', '예상 밖의 감정이 나에 대해 새로 알려준 사실이 있나요?', '감정의 예보와 실제 날씨의 차이를 한 줄로 기록해봐요.'),
  (362, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 감정의 온도가 급격히 변한 시점이 있나요?', 3, '하루 중 갑자기 기분이 차가워지거나 뜨거워진 때가 있나요?', '상황 때문인가요, 아니면 꼬리에 꼬리를 문 생각 때문인가요?', '기분 변화의 패턴을 알면 나를 더 잘 돌볼 수 있어요.'),
  (363, (SELECT id FROM interests WHERE code = 'EMOTION'), '감정이 멈추거나 굳어버린 것 같은 기분이 들었나요?', 3, '어떤 일에도 반응이 늦거나 무감각했던 적이 있나요?', '그게 피로의 신호일까요, 아니면 마음의 공백일까요?', '그 공백에서 나를 다시 끌어올려 준 게 있었다면요?'),
  (364, (SELECT id FROM interests WHERE code = 'EMOTION'), '최근 나를 가장 강하게 흔들어 놓은 감정은 무엇인가요?', 3, '유독 잔상이 오래 남고 강렬했던 마음이 있나요?', '그 감정이 폭풍처럼 몰아쳤던 당시를 떠올려보세요.', '강렬한 감정 아래에 숨어있던 나의 진짜 욕구는 무엇인가요?'),
  (365, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 나를 가장 진 빠지게 만든 감정은 무엇인가요?', 3, '에너지를 쑥 빼앗아 간 소모적인 기분이 있었나요?', '그 감정의 뿌리가 어디까지 닿아 있는지 추적해볼까요?', '다음에 그 감정이 찾아오면 어떻게 마주하고 싶나요?'),
  (366, (SELECT id FROM interests WHERE code = 'EMOTION'), '마음이 무거울 때, 어떻게 행동하나요?', 3, '내 기분의 원인을 스스로 다정하게 물어본 적 있나요?', '이유를 알아냈을 때 마음이 조금 가벼워지는 걸 느꼈나요?', '지금 마음 한구석을 짓누르는 게 있다면 밖으로 꺼내봐요.'),
  (367, (SELECT id FROM interests WHERE code = 'EMOTION'), '이번 주, 아직 차마 꺼내지 못한 감정이 있나요?', 3, '바쁘다는 핑계로 눌러두거나 외면한 마음이 있나요?', '왜 그 감정을 바로 마주하지 못하고 미뤄뒀을까요?', '지금 이 공간에만 살짝 털어놓으면 훨씬 가벼워질 거예요.'),
  (368, (SELECT id FROM interests WHERE code = 'EMOTION'), '지금 내 기분을 딱 한 단어로 정의한다면 뭘까요?', 3, '머릿속을 스치는 가장 직관적인 단어 하나를 골라보세요.', '왜 그 단어가 지금 내 마음의 대표가 되었을까요?', '내일은 어떤 단어로 내 하루를 꾸며보고 싶나요?'),
  (369, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 내가 필사적으로 피하고 싶었던 감정은 무엇인가요?', 3, '마주하기 두렵거나 불편해서 고개를 돌린 게 있나요?', '왜 그것을 피하고 싶었는지 솔직한 마음을 적어보세요.', '완전히 마주하기 힘들다면, 살짝 곁눈질이라도 해볼까요?'),
  (370, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 아침, 눈을 떴을 때 가장 먼저 든 기분은 무엇인가요?', 3, '잠에서 깨어나는 찰나에 나를 맞이한 감정이 무엇이었나요?', '그 첫 기분이 오늘 하루 전체의 색깔을 결정했나요?', '내일 아침엔 어떤 감정의 빛깔로 잠에서 깨고 싶나요?'),
  (371, (SELECT id FROM interests WHERE code = 'EMOTION'), '지금 내 마음의 색깔을 고른다면 어떤 색인가요?', 3, '지금 기분을 색으로 칠한다면 어떤 톤이 어울릴까요?', '그 색은 따뜻한가요, 차가운가요? 아니면 선명한가요?', '내일은 내 마음의 캔버스를 어떤 색으로 채우고 싶나요?'),
  (372, (SELECT id FROM interests WHERE code = 'EMOTION'), '지금 내 마음이 가장 간절하게 외치는 소망은 무엇인가요?', 3, '다른 누구도 아닌, 오직 나만을 위한 바람이 있나요?', '그 바람을 이루기 위해 내가 지금 당장 할 수 있는 건 뭘까요?', '아주 작은 한 걸음, 오늘 바로 시작해볼 수 있을까요?'),
  (373, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘이 지나도 꼭 간직하고 싶은 감정이 있나요?', 3, '사라지지 않고 내일도 내 안에 머물렀으면 하는 기분은?', '그 기분이 나를 찾아온 특별한 순간을 기록해두세요.', '나중에 힘들 때 꺼내 볼 수 있도록 짧은 편지를 남겨봐요.'),
  (374, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 느낀 감정 중 다시 느끼고 싶지 않은 건 무엇인가요?', 3, '나를 힘들게 했거나 불편하게 했던 불청객 같은 감정은?', '그 감정이 나를 찾아오게 된 원인이 무엇이었을까요?', '다음번엔 그 감정에게 문을 열어주지 않을 방법이 있을까요?'),
  (375, (SELECT id FROM interests WHERE code = 'EMOTION'), '이번 주 통틀어 가장 환하게 웃었던 기쁜 순간은?', 3, '세상을 다 가진 듯 마음이 환해졌던 찰나가 있나요?', '그 기쁨은 예상치 못한 선물이었나요, 나의 노력 끝에 왔나요?', '비슷한 기쁨을 다음 주에도 나에게 선물할 수 있을까요?'),
  (376, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 감정을 말로 설명하기 참 어려웠던 순간은?', 3, '단어 하나로 정의할 수 없는 묘한 기분을 느꼈나요?', '그 감정을 날씨나 풍경으로 비유한다면 어떤 모습일까요?', '이름을 붙이지 않아도 괜찮아요. 그 감정이 남긴 느낌은 뭘까요?'),
  (377, (SELECT id FROM interests WHERE code = 'EMOTION'), '오늘 완전히 방전됐다가 다시 충전된 순간이 있나요?', 3, '에너지가 바닥났을 때 나를 다시 일으켜 세운 건 무엇인가요?', '몸의 휴식이었나요, 아니면 누군가의 따뜻한 한마디였나요?', '나만의 ''급속 충전 루틴''을 하나 정해볼 수 있을까요?'),
  (378, (SELECT id FROM interests WHERE code = 'EMOTION'), '하나의 감정만 느낄 수 있다면 무엇을 남기고 싶나요?', 3, '기쁨, 슬픔, 평온, 설렘 등 자유롭게 떠올려봐요.', '왜 그 감정을 선택했나요?', '그 선택이 나에게 가장 중요한 가치를 보여주고 있나요?'),
  (379, (SELECT id FROM interests WHERE code = 'EMOTION'), '가장 많이 울었던 날은 언제였나요?', 3, '떠올려도 괜찮은 범위에서 생각해봐요.', '그날 눈물이 멈추지 않았던 이유는 뭐였나요?', '그만큼 운 뒤에 나에게 어떤 변화가 있었나요?'),
  (380, (SELECT id FROM interests WHERE code = 'EMOTION'), '하나의 감정을 더이상 느끼지 않을 수 있다면 무엇을 고르고 싶나요?', 3, '다시는 느끼고 싶지 않은 감정이나 유독 약해지는 감정이 있기 마련이에요.', '나에게 힘든 감정은 무엇인지 떠올려봐요.', '그 감정이 사라지면 내 삶은 어떻게 변할까요?');
INSERT INTO daily_questions (id, interest_id, question_text, question_level, empathy_guide, hint_guide, leading_question_guide)
VALUES
  (381, (SELECT id FROM interests WHERE code = 'EMOTION'), '가장 소중한 기억은 무엇인가요?', 3, '시간이 지나도 선명하게 남아 있는 장면을 떠올려봐요.', '그 기억 속에서 어떤 감정을 느꼈나요?', '그 기억이 소중한 이유가 지금의 나에 대해 뭘 말해주나요?'),
  (382, (SELECT id FROM interests WHERE code = 'EMOTION'), '가장 끔찍한 경험은 무엇인가요?', 3, '떠올리기 괜찮은 범위에서만 생각해봐요. 무리하지 않아도 돼요.', '그 경험이 나에게 어떤 흔적을 남겼나요?', '그때의 나와 지금의 나는 어떻게 달라졌나요?'),
  (383, (SELECT id FROM interests WHERE code = 'EMOTION'), '내 모습을 숨김없이 다 보여준다면 어떤 일이 벌어질까요?', 3, '나를 다 보여주면 일어날 것 같은 장면을 솔직하게 하나 적어봐요.', '그 장면이 실제로 일어난 적이 있나요, 아니면 나의 예상인가요?', '아주 작은 범위에서 ''솔직한 나''를 보여줄 상황을 떠올려봐요.'),
  (384, (SELECT id FROM interests WHERE code = 'EMOTION'), '나조차 이해가 안 되는 내 모습은 어떤 것인가요?', 3, '"왜 나는 이러지?"라고 느꼈던 낯선 순간을 하나 떠올려봐요.', '그 이해 안 되는 부분이 내 일상과 관계에 어떤 영향을 주나요?', '그 부분에게 "난 너를 잘 모르겠지만..."이라며 편지를 써볼까요?'),
  (385, (SELECT id FROM interests WHERE code = 'EMOTION'), '나의 어떤 면을 아직 ''괜찮아''라고 해주지 못하고 있나요?', 3, '감추고 싶거나 바꾸고 싶은 내 모습을 하나 가만히 떠올려봐요.', '그게 ''안 괜찮다''고 느끼게 된 건 언제부터, 누구 때문이었나요?', '소중한 친구가 같은 고민을 한다면 나는 뭐라고 토닥여줄까요?'),
  (386, (SELECT id FROM interests WHERE code = 'EMOTION'), '지금 힘든 시간이 내게 가르쳐주는 게 있다면 뭘까요?', 3, '지금 겪는 힘든 상황과 그때의 감정을 한 문장으로 적어봐요.', '"이걸 통해 나는 ___을 배우고 있다"로 문장을 완성해볼까요?', '이 시간을 잘 지나온 미래의 내가 지금의 나에게 말해준다면요?'),
  (387, (SELECT id FROM interests WHERE code = 'EMOTION'), '정말 싫은 것이 나에게 주는 이득이 혹시 있을까요?', 3, '정말 싫어하는 상황이나 사람, 감정을 하나 떠올려봐요.', '그것이 혹시 나를 보호하거나 숨게 해주는 이득을 주진 않나요?', '그 이득 없이도 괜찮다면 나는 어떤 새로운 선택을 하고 싶나요?'),
  (388, (SELECT id FROM interests WHERE code = 'EMOTION'), '내 삶에서 ''들키면 안 돼''라고 느끼는 부분이 있나요?', 3, '아무도 보지 않는 곳에 "사실은..."으로 시작하는 글을 적어봐요.', '그걸 숨기기 위해 내가 얼마나 많은 마음의 에너지를 쓰고 있나요?', '그 진실의 아주 작은 조각을 나 자신에게만이라도 인정해봐요.'),
  (389, (SELECT id FROM interests WHERE code = 'EMOTION'), '감정이 표정에 잘 드러나는 편인가요?', 3, '주변에서 표정 읽기 쉽다는 말을 듣는지 떠올려봐요.', '드러나는 게 편한가요, 불편한가요?', '감정을 숨기고 싶을 때와 보여주고 싶을 때의 차이는 뭔가요?'),
  (390, (SELECT id FROM interests WHERE code = 'EMOTION'), '감정에 쉽게 휘둘리는 편인가요?', 3, '기분에 따라 행동이 달라지는지 생각해봐요.', '어떤 감정에 가장 약한 것 같나요?', '감정에 휘둘리는 것과 감정에 솔직한 것, 차이가 있나요?'),
  (391, (SELECT id FROM interests WHERE code = 'EMOTION'), '가장 실망하는 순간은 어떤 때인가요?', 5, '최근에 실망했던 경험을 떠올려봐요.', '실망의 원인이 나인가요, 상대인가요, 상황인가요?', '실망이 반복되는 패턴이 있나요?'),
  (392, (SELECT id FROM interests WHERE code = 'EMOTION'), '남들보다 자주 느끼는 감정은 무엇인가요?', 3, '하루 중 가장 자주 찾아오는 감정을 떠올려봐요.', '그 감정이 자주 오는 이유가 뭘까요?', '그 감정이 나를 정의한다고 느끼나요?'),
  (393, (SELECT id FROM interests WHERE code = 'EMOTION'), '감정을 추스리고 대화하는 걸 선호하나요, 아니면 대화를 통해 감정을 추스리는 걸 좋아하나요?', 5, '갈등이나 감정적 상황에서의 나를 떠올려봐요.', '두 방식을 각각 써본 적 있나요?', '나의 방식이 관계에 어떤 영향을 주나요?'),
  (394, (SELECT id FROM interests WHERE code = 'EMOTION'), '타인에게 감정이 많이 영향을 받는 편인가요?', 5, '주변 사람의 기분에 따라 내 기분이 어떻게 바뀌는지 떠올려봐요.', '하나의 감정만 느낄 수 있다면 무엇을 남기고 싶나요?', '하나의 감정만 느낄 수 있다면 무엇을 남기고 싶나요?'),
  (395, (SELECT id FROM interests WHERE code = 'EMOTION'), '화가 나면 어떻게 표현하나요?', 3, '소리를 지르거나, 참거나, 울거나 등이요.', '그 방식이 된 건 언제부터인가요?', '화를 표현하는 방식에 만족하나요?'),
  (396, (SELECT id FROM interests WHERE code = 'EMOTION'), '참다 참다 폭발한 적 있나요?', 3, '쌓인 감정이 터진 경험이요.', '그때 어떤 일이 있었나요?', '폭발 후에 어떤 감정이 들었나요?'),
  (397, (SELECT id FROM interests WHERE code = 'EMOTION'), '짜증이 나는 포인트가 정해져 있나요?', 3, '반복적으로 짜증나는 상황이요.', '왜 그 부분에 민감한 것 같나요?', '짜증 포인트가 나의 가치관과 연결되나요?'),
  (398, (SELECT id FROM interests WHERE code = 'EMOTION'), '화난 감정을 오래 가져가는 편인가요?', 3, '금방 풀리는지, 오래가는지요.', '화가 안 풀릴 때 어떻게 하나요?', '용서와 잊음의 차이는 뭔가요?'),
  (399, (SELECT id FROM interests WHERE code = 'EMOTION'), '울고 싶은데 못 운 적 있나요?', 3, '눈물이 안 나왔던 경험이요.', '왜 울지 못했나요?', '참은 감정은 어디로 갔을까요?'),
  (400, (SELECT id FROM interests WHERE code = 'EMOTION'), '혼자 울 때와 누군가 앞에서 울 때가 다른가요?', 3, '각각의 상황을 떠올려봐요.', '어느 쪽이 더 편한가요?', '눈물을 보여주는 것이 나에게 어떤 의미인가요?'),
  (401, (SELECT id FROM interests WHERE code = 'EMOTION'), '슬픈 노래나 영화를 일부러 찾아보는 편인가요?', 3, '슬픈 콘텐츠에 끌리는지요.', '그럴 때 어떤 기분이 드나요?', '슬픔을 일부러 느끼는 것이 카타르시스인가요?'),
  (402, (SELECT id FROM interests WHERE code = 'EMOTION'), '가장 위로가 되는 말은 무엇인가요?', 3, '힘들 때 듣고 싶은 말을 떠올려봐요.', '왜 그 말이 위로가 되나요?', '나에게 필요한 위로의 방식은 뭔가요?'),
  (403, (SELECT id FROM interests WHERE code = 'EMOTION'), '밤에 갑자기 불안해진 적 있나요?', 3, '이유 없이 마음이 무거워진 경험이요.', '그때 어떻게 대처했나요?', '불안의 정체가 뭐라고 생각하나요?'),
  (404, (SELECT id FROM interests WHERE code = 'EMOTION'), '실패가 두려운 편인가요?', 3, '도전 앞에서 망설인 경험을 떠올려봐요.', '두려움이 나를 멈추게 한 적 있나요?', '두려움이 나를 보호하는 건가요, 가두는 건가요?'),
  (405, (SELECT id FROM interests WHERE code = 'EMOTION'), '걱정이 많은 편인가요?', 3, '아직 일어나지 않은 일을 미리 걱정하는지요.', '걱정이 도움이 된 적 있나요?', '걱정과 준비의 차이는 뭔가요?'),
  (406, (SELECT id FROM interests WHERE code = 'EMOTION'), '혼자 있으면 불안한가요?', 3, '혼자만의 시간이 편한지, 불안한지요.', '사람이 없으면 뭐가 달라지나요?', '외로움과 불안은 같은 건가요, 다른 건가요?'),
  (407, (SELECT id FROM interests WHERE code = 'EMOTION'), '미래가 불안한 적 있나요?', 3, '앞으로의 삶에 대한 막연한 걱정이요.', '어떤 부분이 가장 불안한가요?', '불안을 다루는 나만의 방법이 있나요?'),
  (408, (SELECT id FROM interests WHERE code = 'EMOTION'), '감정이 없다면 어떤 삶일까요?', 3, '기쁨도 슬픔도 없는 상태를 상상해봐요.', '그게 편할 것 같나요, 공허할 것 같나요?', '감정이 나에게 어떤 역할을 하고 있나요?'),
  (409, (SELECT id FROM interests WHERE code = 'EMOTION'), '나이가 들면서 감정이 변했나요?', 3, '예전과 지금의 차이를 떠올려봐요.', '어떤 감정이 더 커졌거나 작아졌나요?', '감정의 변화가 성장인가요, 무뎌진 건가요?'),
  (410, (SELECT id FROM interests WHERE code = 'EMOTION'), '감정을 글로 쓰면 정리가 되나요?', 3, '일기나 메모로 감정을 풀어본 적 있나요?', '쓰고 나면 뭐가 달라지나요?', '정리한 글을 되돌아보기도 하나요?'),
  (411, (SELECT id FROM interests WHERE code = 'EMOTION'), '감정의 회복 속도가 빠른 편인가요?', 3, '힘든 일 후 돌아오는 시간을 떠올려봐요.', '빨리 회복하는 편인가요, 오래 가나요?', '회복 속도가 나에 대해 뭘 말해주나요?'),
  (412, (SELECT id FROM interests WHERE code = 'EMOTION'), '고마운 마음을 잘 표현하는 편인가요?', 3, '감사를 전한 경험을 떠올려봐요.', '표현하기 어려운 이유가 있나요?', '감사를 표현하면 관계가 어떻게 달라지나요?'),
  (413, (SELECT id FROM interests WHERE code = 'EMOTION'), '미안하다는 표현을 잘하는 편인가요?', 3, '모든 표현이 중요하지만 미안한 마음을 잘 전달하는 건 정말 중요해요.', '최근 미안했던 적이 있다면, 그 때 나는 어떻게 행동했나요?', '미안함을 잘 표현하지 못한다면 왜 그럴까요?'),
  (414, (SELECT id FROM interests WHERE code = 'ROUTINE'), '아침형 인간인가요 저녁형 인간인가요?', 3, '생활루틴은 사람별로 다양해요.', '미라클 모닝을 즐기는 아침형 인간 또는 나만의 밤을 즐기는 저녁형 인간 중 어디에 더 가까운가요?', '이 생활 패턴의 장점과 단점도 생각해봐요.'),
  (415, (SELECT id FROM interests WHERE code = 'ROUTINE'), '계획이 바뀌었을 때 어떻게 행동하나요?', 3, '완벽한 계획을 세웠다고 생각해도 어쩔 수 없이 계획이 바뀌기도 해요.', '갑자기 아파서 가지 못하게 된 여행을 생각해보세요.', '계획이 나에게 어떤 안정감을 주는지 떠올려봐요.'),
  (416, (SELECT id FROM interests WHERE code = 'ROUTINE'), '워라벨이 중요한가요?', 3, '워라벨과 성과 또는 보상 중에 하나를 고른다면 어느 쪽을 선택하고 싶나요?', '일과 삶 중 어느 것에 가중치를 두어 생각하는지 떠올려봐요.', '왜 그렇게 생각하게 되었는지도 써볼까요?'),
  (417, (SELECT id FROM interests WHERE code = 'ROUTINE'), '최근에 시작한 일 중 루틴에 넣고 싶은 일이 있나요?', 3, '고양이들은 재밌었던 일은 하루 일과에 추가한다고 해요.', '한 번으로 끝내기에는 아쉬운 일들이 있죠.', '어떻게 계속 해보고 싶은지 생각해봐요.'),
  (418, (SELECT id FROM interests WHERE code = 'ROUTINE'), '휴대폰을 바꾸는 주기가 어떻게 되나요?', 3, '새로운 휴대폰으로 바꾸며 신선한 기능을 경험하는 사람도 있고', '하나의 휴대폰을 길게 사용하다 고장날 때 즈음 바꾸는 사람도 있어요.', '어떤 유형인지, 왜 그렇게 하는지 써봐요.'),
  (419, (SELECT id FROM interests WHERE code = 'ROUTINE'), '잠 들기 전 꼭 하는 일이 있나요?', 3, '자기 전에 릴스 보기, 팩 붙이기 또는 스트레칭하기 등 다양한 활동을 하곤 해요.', '자기 전에 그 일을 하는 이유는 무엇인가요?', '자기 전 루틴으로 추가하고 싶은 일이 있나요?'),
  (420, (SELECT id FROM interests WHERE code = 'ROUTINE'), '약속 없는 휴일엔 뭘 하나요?', 3, '이불 속에서 뒹굴거리기, 넷플릭스 정주행처럼 사소한 것도 좋아요.', '지난 휴일에 뭘했는지 떠올려봐요.', '그걸 할 때 어떤 기분이었나요?'),
  (421, (SELECT id FROM interests WHERE code = 'ROUTINE'), '지하철이나 버스에서 주로 무엇을 하며 시간을 보내나요?', 3, '이동 시간도 나만의 방식으로 채울 수 있어요.', '음악 듣기, 창밖 보기 혹은 스마트폰 보기를 생각해보세요.', '그 시간을 그렇게 보내면 어떤 기분이 드나요?'),
  (422, (SELECT id FROM interests WHERE code = 'ROUTINE'), '나도 모르게 반복하는, 조금 신경 쓰이는 버릇은?', 3, '할 때마다 마음 한구석이 찝찝한 행동이 있나요?', '그 사소한 버릇이 나의 하루 컨디션을 어떻게 좌우하나요?', '내일 당장 실천해볼 수 있는 아주 귀여운 변화 하나는?'),
  (423, (SELECT id FROM interests WHERE code = 'ROUTINE'), '오늘 나를 정신없이 달리게 만든 주범은 누구?', 3, '가장 분주하고 숨 가빴던 시간대를 떠올려 보세요.', '그 달리기는 나를 위한 설렘이었나요, 등 떠밀린 의무였나요?', '나를 소진시키기만 한 건지, 아니면 채워주기도 했는지 돌아봐요.'),
  (424, (SELECT id FROM interests WHERE code = 'ROUTINE'), '딱 5분만 투자해서 매일 하고 싶은 작은 습관은?', 3, '"언젠가 해야지"라며 마음의 짐처럼 둔 일이 있나요?', '하루 5분이라면 어디서부터 가볍게 시작할 수 있을까요?', '일주일 후, 이 약속을 지킨 멋진 나에게 미리 한마디!'),
  (425, (SELECT id FROM interests WHERE code = 'ROUTINE'), '오늘 아무 생각 없이 기계적으로 반복한 행동은?', 3, '무의식중에 튀어나온 말투나 습관적인 동작이 있었나요?', '그 반복적인 행동 속에 숨겨진 나의 심리는 무엇일까요?', '그 행동이 나를 편안하게 하나요, 아니면 바꾸고 싶나요?'),
  (426, (SELECT id FROM interests WHERE code = 'ROUTINE'), '오늘 나의 에너지를 가장 많이 잡아먹은 일은?', 3, '체력과 정신력을 가장 많이 쏟아부은 활동 하나는?', '그 소모가 보람찬 수확이었나요, 아니면 허무한 낭비였나요?', '내일은 나의 소중한 연료를 어디에 더 집중하고 싶나요?'),
  (427, (SELECT id FROM interests WHERE code = 'ROUTINE'), '오늘 몸이 가장 바쁘게 움직였던 골든타임은?', 3, '평소보다 부지런히 움직였던 시간이나 상황이 있었나요?', '나를 움직이게 한 원동력은 무엇이었는지 짚어보세요.', '내가 가장 효율적으로 움직이는 조건을 발견했나요?'),
  (428, (SELECT id FROM interests WHERE code = 'ROUTINE'), '계속 미루고 있는 일 하나를 지금 꺼낸다면?', 3, '마음 한구석에 무겁게 얹혀 있는 숙제 같은 일은?', '왜 그 일을 자꾸 뒤로 미루게 되는지 솔직히 적어볼까요?', '5분 안에 끝낼 수 있는 가장 쉬운 첫 단계부터 정해봐요.'),
  (429, (SELECT id FROM interests WHERE code = 'ROUTINE'), '요즘 내 삶에 기분 좋게 스며든 나만의 루틴은 무엇인가요?', 3, '반복할수록 마음이 편안해지는 나만의 루틴이 생겼나요?', '그 리듬이 나에게 참 잘 맞는다고 느끼는 이유는 무엇인가요?', '이 건강한 흐름을 오래 지키기 위해 필요한 노력이 있다면?'),
  (430, (SELECT id FROM interests WHERE code = 'ROUTINE'), '오늘 조금 과하다 싶었던 나의 행동은 무엇이었나요?', 3, '"이건 좀 줄여야겠다"라고 반성하게 된 순간이 있나요?', '건강을 위해서인가요, 아니면 마음의 평화를 위해서인가요?', '단번에 끊기보다 아주 조금씩 줄여가는 나만의 전략은?'),
  (431, (SELECT id FROM interests WHERE code = 'ROUTINE'), '오늘 하루 종일 가장 많이 반복한 행동은 무엇이었나요?', 3, '나도 모르게 손이 가거나 입에 붙은 습관이 있었나요?', '불안해서 그랬을까요, 아니면 그저 편해서 그랬을까요?', '계속 가져가고 싶은 습관인지, 작별하고 싶은 습관인지 정해봐요.'),
  (432, (SELECT id FROM interests WHERE code = 'ROUTINE'), '오늘은 하루를 계획적으로 보냈나요 아니면 즉흥적으로 보냈나요?', 3, '꽉 짜인 일정 속에서 움직였나요, 아니면 즉흥적이었나요?', '오늘 하루를 보낸 방식이 나에게 어떤 기분을 선물했나요?', '나에게 가장 잘 어울리는 ''하루의 모양''을 그려보세요.'),
  (433, (SELECT id FROM interests WHERE code = 'ROUTINE'), '오늘 나의 루틴 속에서 얻은 가장 칭찬해주고 싶은 성공은 무엇인가요?', 3, '어김없이 해낸 나만의 작은 약속이 있나요?', '그 작은 성공이 오늘 나의 자존감을 얼마나 높여주었나요?', '내일은 어떤 루틴을 더 견고하게 지켜내고 싶나요?'),
  (434, (SELECT id FROM interests WHERE code = 'ROUTINE'), '아침이나 저녁, 평소와 달랐던 순간은 언제였나요?', 3, '시작이나 마무리의 리듬이 깨졌거나 바뀐 부분이 있나요?', '그 변화가 나에게 신선한 자극이었나요, 아니면 불편했나요?', '더 기분 좋은 내일을 위해 오늘 저녁에 꼭 하고 싶은 건?'),
  (435, (SELECT id FROM interests WHERE code = 'ROUTINE'), '오늘 정리한 나의 생활이나 마음은 무엇이었나요?', 3, '흐트러진 물건이나 복잡한 생각을 치워버린 순간은?', '정리하고 난 뒤에 찾아온 마음의 공간은 어떤 느낌인가요?', '지금 바로 정리하고 싶은 마음의 짐이 하나 더 있다면?'),
  (436, (SELECT id FROM interests WHERE code = 'ROUTINE'), '계획보다 시간이 훨씬 더 오래 걸린 일은 무엇인가요?', 3, '예상 밖의 복병을 만나 시간을 많이 쓴 작업이 있나요?', '왜 시간이 지체되었는지 원인을 차분히 분석해볼까요?', '다음에 비슷한 일을 할 때 활용할 수 있는 나만의 팁은?'),
  (437, (SELECT id FROM interests WHERE code = 'ROUTINE'), '손이 안 가서 끝까지 붙잡고 있었던 일이 있나요?', 3, '하기 싫어서 계속 미루다가 겨우 끝낸 게 무엇인가요?', '의욕이 생기지 않았던 진짜 이유는 피로인가요, 재미인가요?', '최소한의 동기부여를 위해 나에게 어떤 보상을 해줄까요?'),
  (438, (SELECT id FROM interests WHERE code = 'ROUTINE'), '운동을 시작하게 된 계기가 있나요?', 3, '건강, 다이어트, 스트레스 해소 등 뭐든 괜찮아요.', '그 계기가 지금도 동기부여가 되나요?', '운동이 나에게 어떤 의미로 변해왔나요?'),
  (439, (SELECT id FROM interests WHERE code = 'ROUTINE'), '주로 어떤 운동을 하나요?', 3, '헬스, 러닝, 수영 등 떠오르는 대로 적어봐요.', '그 운동을 선택한 이유가 있나요?', '그 운동이 나의 성격과 닮은 점이 있나요?'),
  (440, (SELECT id FROM interests WHERE code = 'ROUTINE'), '일주일에 몇 번 운동하나요?', 3, '정확하지 않아도 괜찮아요. 대략적으로요.', '그 횟수에 만족하나요?', '이상적인 횟수와 현실의 차이는 왜 생기나요?'),
  (441, (SELECT id FROM interests WHERE code = 'ROUTINE'), '운동은 주로 언제 하나요?', 3, '아침, 점심, 저녁 중 언제가 많은지 떠올려봐요.', '그 시간대를 선택한 이유가 있나요?', '시간대가 운동 효과나 기분에 영향을 주나요?'),
  (442, (SELECT id FROM interests WHERE code = 'ROUTINE'), '공부나 작업을 시작하기 전에 꼭 하는 게 있나요?', 3, '커피 내리기, 책상 정리, 음악 틀기 등 나만의 루틴이 있다면 떠올려봐요.', '그 루틴이 없으면 시작이 잘 안 되나요?', '시작 전 루틴이 나에게 어떤 역할을 하고 있을까요?'),
  (443, (SELECT id FROM interests WHERE code = 'ROUTINE'), '집중이 잘 되는 시간대가 있나요?', 3, '아침, 낮, 밤 중 언제 머리가 가장 잘 돌아가는지 떠올려봐요.', '그 시간대를 잘 활용하고 있나요?', '내 집중 리듬을 안다는 게 나에게 어떤 도움을 주나요?'),
  (444, (SELECT id FROM interests WHERE code = 'ROUTINE'), '어디서 공부하는 게 가장 잘 되나요?', 3, '집, 카페, 도서관, 스터디카페 등 주로 가는 곳을 떠올려봐요.', '그 장소의 어떤 점이 나에게 맞나요?', '공간이 바뀌면 집중력도 바뀌나요?'),
  (445, (SELECT id FROM interests WHERE code = 'ROUTINE'), '공부할 때 음악을 듣는 편인가요?', 3, '틀어놓는 음악이 있다면 어떤 종류인지 떠올려봐요.', '음악이 집중에 도움이 되나요?', '소리가 있는 환경과 조용한 환경 중 나에게 더 맞는 건 어떤 쪽이에요?'),
  (446, (SELECT id FROM interests WHERE code = 'ROUTINE'), '한 번 집중하면 오래 가는 편인가요?', 3, '몰입하면 시간 가는 줄 모르는 편인지 떠올려봐요.', '집중이 끊기는 순간이 있다면 주로 어떤 때예요?', '나의 집중력 패턴이 나에 대해 뭘 말해주나요?'),
  (447, (SELECT id FROM interests WHERE code = 'ROUTINE'), '멀티태스킹을 잘하는 편이에요?', 3, '여러 가지를 동시에 하는 편인지 하나에 몰두하는 편인지 떠올려봐요.', '어떤 방식이 더 효율적이라고 느끼나요?', '나의 작업 방식이 나의 성격과 닮은 부분이 있나요?'),
  (448, (SELECT id FROM interests WHERE code = 'ROUTINE'), '공부하다 막히면 어떻게 하나요?', 3, '이해가 안 되거나 진도가 안 나갈 때 어떤 반응이 오는지 떠올려봐요.', '바로 질문하는 편이에요? 혼자 끙끙대는 편이에요?', '막혔을 때의 대처 방식이 다른 상황에서도 비슷하게 나타나나요?'),
  (449, (SELECT id FROM interests WHERE code = 'ROUTINE'), '타이머나 시간 관리 도구를 쓰나요?', 3, '뽀모도로, 타이머, 플래너 등 쓰고 있는 게 있다면 떠올려봐요.', '그게 실제로 도움이 되나요?', '시간을 관리하려는 것이 나에게 안정감을 주나요?'),
  (450, (SELECT id FROM interests WHERE code = 'ROUTINE'), '공부할 때 핸드폰을 어떻게 하나요?', 3, '치워두는 편인지, 옆에 두는 편인지 떠올려봐요.', '핸드폰 때문에 집중이 깨진 적이 얼마나 자주 있나요?', '핸드폰과의 거리가 집중력과 어떤 관계가 있는 것 같나요?'),
  (451, (SELECT id FROM interests WHERE code = 'ROUTINE'), '번아웃이 온 적 있나요?', 3, '더 이상 못 하겠다 싶었던 경험이 있다면 떠올려봐요.', '그때 어떻게 회복했나요?', '번아웃의 신호를 미리 알아채는 편이에요?'),
  (452, (SELECT id FROM interests WHERE code = 'ROUTINE'), '공부하다 쉴 때 뭘 하나요?', 3, '쉬는 시간에 하는 행동을 떠올려봐요.', '그게 진짜 쉼이 되나요?', '쉬는 것과 딴짓의 경계가 어디쯤이에요?'),
  (453, (SELECT id FROM interests WHERE code = 'ROUTINE'), '쉬는 게 불안한 적 있나요?', 3, '쉬면서도 뭔가 해야 할 것 같은 느낌이 든 적이 있다면 떠올려봐요.', '그 불안이 어디서 오는 건지 생각해봐요.', '쉬는 것도 나를 위한 일이라고 느끼나요?'),
  (454, (SELECT id FROM interests WHERE code = 'ROUTINE'), '잘하고 싶은 마음과 해야 하는 마음 중 뭐가 더 크나요?', 3, '지금 하고 있는 것에 대한 솔직한 마음을 떠올려봐요.', '두 마음의 비율이 어떻게 되나요?', '그 비율이 만족스러운가요?'),
  (455, (SELECT id FROM interests WHERE code = 'ROUTINE'), '시험이나 발표 전에 긴장하는 편이에요?', 3, '중요한 순간 앞에서의 나를 떠올려봐요.', '긴장이 도움이 되는 편이에요?', '긴장을 다루는 나만의 방법이 있나요?'),
  (456, (SELECT id FROM interests WHERE code = 'ROUTINE'), '공부할 떄 간식이나 음료가 옆에 있어야 하나요?', 3, '작업할 때 옆에 두는 것들이 있다면 떠올려봐요.', '간식을 먹는 게 집중에 도움이 되나요?', '작업 중 먹는 것이 나에게 보상이에요?'),
  (457, (SELECT id FROM interests WHERE code = 'ROUTINE'), '물건을 잘 버리는 편인가요?', 3, '안 쓰는 물건을 두고 고민했던 경험을 떠올려봐요.', '버리기 어려운 이유가 뭔 것 같나요?', '물건에 대한 집착이 다른 것에 대한 태도와 비슷한가요?'),
  (458, (SELECT id FROM interests WHERE code = 'ROUTINE'), '물건의 자리가 정해져 있나요?', 3, '항상 같은 곳에 두는 물건이 있다면 떠올려봐요.', '자리가 안 정해져 있으면 자주 잃어버리나요?', '정해진 자리가 나에게 어떤 안정감을 주나요?'),
  (459, (SELECT id FROM interests WHERE code = 'ROUTINE'), '지금 내 방 상태가 어떤가요?', 3, '방을 둘러보면서 솔직하게 떠올려봐요.', '방 상태에 만족하나요?', '지금 방 상태가 요즘 내 마음 상태와 비슷한 것 같나요?'),
  (460, (SELECT id FROM interests WHERE code = 'ROUTINE'), '어지러운 방에서도 편한 편인가요?', 3, '어수선한 공간에서의 나를 떠올려봐요.', '정리 안 된 공간이 스트레스를 주나요?', '정돈에 대한 기준이 나에게 어디서 온 건지 생각해봐요.');
INSERT INTO daily_questions (id, interest_id, question_text, question_level, empathy_guide, hint_guide, leading_question_guide)
VALUES
  (461, (SELECT id FROM interests WHERE code = 'ROUTINE'), '누군가 내 방에 오면 신경 쓰이나요?', 3, '손님이 온다고 할 때 급하게 치운 경험이 있다면 떠올려봐요.', '평소의 내 공간과 보여주는 공간이 다른가요?', '남에게 보이는 공간과 나만의 공간 사이에서 나는 어떤 사람이에요?'),
  (462, (SELECT id FROM interests WHERE code = 'ROUTINE'), '지금 당장 버리고 싶은 것이 있나요?', 3, '없어지면 시원할 것 같은 물건을 떠올려봐요.', '왜 아직 안 버렸나요?', '버리지 못하는 것이 나에 대해 뭘 말해주나요?'),
  (463, (SELECT id FROM interests WHERE code = 'ROUTINE'), '청소를 얼마나 자주 하나요?', 3, '매일, 주 1회, 한 달에 한 번 등 대략적으로 떠올려봐요.', '그 주기에 만족하나요?', '청소 주기가 나의 생활 패턴을 보여주는 것 같나요?'),
  (464, (SELECT id FROM interests WHERE code = 'ROUTINE'), '운동할 때 꼭 듣는 음악이 있나요?', 3, '플레이리스트가 있다면 어떤 분위기인지 떠올려봐요.', '음악이 운동에 어떤 영향을 주나요?', '그 음악 취향이 나의 운동 스타일을 말해주나요?'),
  (465, (SELECT id FROM interests WHERE code = 'ROUTINE'), '운동 전 루틴이 있나요?', 3, '스트레칭, 커피, 음악 틀기 등 작은 것도 괜찮아요.', '그 루틴이 없으면 운동 느낌이 달라지나요?', '준비 과정이 나에게 어떤 역할을 하나요?'),
  (466, (SELECT id FROM interests WHERE code = 'ROUTINE'), '운동 후 꼭 하는 것이 있나요?', 3, '샤워, 프로틴, 셀카 등 뭐든 떠올려봐요.', '그게 왜 중요하게 느껴지나요?', '운동 후 루틴이 성취감과 연결되나요?'),
  (467, (SELECT id FROM interests WHERE code = 'ROUTINE'), '운동할 때 혼자하는 것과 같이 하는 것 중 무엇이 더 좋은가요?', 3, '평소 어떤 쪽이 더 많은지 생각해봐요.', '그 선호가 생긴 이유가 있나요?', '운동할 때의 나는 평소의 나와 비슷한가요?'),
  (468, (SELECT id FROM interests WHERE code = 'ROUTINE'), '운동할 때 거울을 자주 보나요?', 3, '자세 확인이든, 몸 변화 확인을 위해서 거울을 활용할 수 있어요.', '거울 속 나를 볼 때 어떤 기분인가요?', '그 외에도 운동할 때의 습관이 있는지 떠올려봐요.'),
  (469, (SELECT id FROM interests WHERE code = 'ROUTINE'), '운동하기 싫은 날은 어떻게 하나요?', 3, '쉬는 날도 있고, 억지로 가는 날도 있잖아요.', '그 선택의 기준은 뭔가요?', '나만의 동기부여 방법이 있나요?'),
  (470, (SELECT id FROM interests WHERE code = 'ROUTINE'), '운동 목표가 있나요?', 3, '체중, 근육량, 기록 등 구체적이든 막연하든 괜찮아요.', '그 목표를 세운 이유가 있나요?', '목표가 나를 움직이게 하나요, 부담을 주나요?'),
  (471, (SELECT id FROM interests WHERE code = 'ROUTINE'), '운동 기록을 남기는 편인가요?', 3, '앱, 수첩, 사진 등 어떤 방식이든요.', '기록이 동기부여에 도움이 되나요?', '기록하는 습관이 다른 영역에도 영향을 주나요?'),
  (472, (SELECT id FROM interests WHERE code = 'ROUTINE'), '운동으로 성취감을 느낀 적 있나요?', 3, '작은 것이라도 괜찮아요. 떠오르는 순간이 있나요?', '그때 어떤 기분이었나요?', '그 성취감이 삶의 다른 부분에도 영향을 줬나요?'),
  (473, (SELECT id FROM interests WHERE code = 'ROUTINE'), '가격 비교를 꼼꼼히 하는 편인가요?', 3, '여러 사이트를 돌아보면서 소비하는 편인가요?', '소비에서 뭘 더 우선순위에 두고 결정하는지 생각해봐요.', '절약과 시간 중 뭐가 더 중요한가요?'),
  (474, (SELECT id FROM interests WHERE code = 'ROUTINE'), '한 달에 가장 많이 쓰는 카테고리가 뭔가요?', 3, '식비, 교통비, 쇼핑 등 다양한 소비를 하게 되죠.', '그 비중에 만족하나요?', '소비의 비중을 바꾼다면 어떻게 바꾸고 싶나요?'),
  (475, (SELECT id FROM interests WHERE code = 'ROUTINE'), '누군가에게 돈 쓰는 게 좋은 편인가요?', 3, '선물, 밥 사기 등으로 누군가에게 돈을 썼을 때의 감정을 떠올려봐요.', '줄 때 어떤 기분이 드나요?', '나를 위한 소비와 남을 위한 소비, 어느 쪽이 더 만족스러운가요?'),
  (476, (SELECT id FROM interests WHERE code = 'ROUTINE'), '소비 습관 중 바꾸고 싶은 게 있나요?', 3, '후회했던 소비들의 공통점이 있나요?', '왜 후회하는지, 그리고 왜 아직 못 바꿨는지 떠올려봐요.', '이상적인 나의 소비 모습은 어떤 건가요?'),
  (477, (SELECT id FROM interests WHERE code = 'ROUTINE'), '나에게 ''돈''이란 한마디로 뭔가요?', 3, '떠오르는 단어나 이미지가 있나요?', '그 표현이 왜 떠올랐나요?', '돈에 대한 나의 태도가 삶의 가치관에 어떻게 녹아있나요?'),
  (478, (SELECT id FROM interests WHERE code = 'ROUTINE'), '돈을 빌려본 적 있나요?', 3, '친구나 가족에게 빌린 경험을 떠올려봐요.', '그때 어떤 기분이었나요?', '빌리는 것에 대한 나의 감정이 자존감과 연결되나요?'),
  (479, (SELECT id FROM interests WHERE code = 'ROUTINE'), '나에게 투자할 가치가 있는 분야는 뭔가요?', 5, '교육, 건강, 외모, 경험 등 각자 다양한 분야에 투자하곤 해요.', '아쉬운 부분을 채우고 싶은지, 강점을 더 발전시키고 싶은지 떠올려봐요.', '자기 투자의 기준이 시간이 지나며 바뀌었나요?'),
  (480, (SELECT id FROM interests WHERE code = 'ROUTINE'), '10년 후 나의 경제적 모습은 어떨 것 같나요?', 3, '미래의 경제 상황을 상상해봐요.', '그 모습을 위해 지금 뭘 하고 있나요?', '경제적 미래를 생각하면 어떤 감정이 드나요?'),
  (481, (SELECT id FROM interests WHERE code = 'ROUTINE'), '구독 서비스에 얼마나 쓰고 있나요?', 3, '넷플릭스, 음악, 앱 등이요.', '다 쓰고 있나요?', '안 쓰는 구독을 유지하는 이유는 뭔가요?'),
  (482, (SELECT id FROM interests WHERE code = 'ROUTINE'), '꿈을 자주 꾸나요?', 3, '아침에 일어나서 꿈이 기억나는 편인지 떠올려봐요.', '기억나는 꿈은 주로 어떤 느낌이에요?', '꿈에서 반복적으로 느끼는 감정이 현실의 나와 연결되는 부분이 있나요?'),
  (483, (SELECT id FROM interests WHERE code = 'ROUTINE'), '꿈을 기록해본 적 있나요?', 3, '꿈 일기를 쓰거나 깨자마자 메모해본 경험이 있다면 떠올려봐요.', '기록하니까 꿈이 더 선명해지거나 패턴이 보이던가요?', '꿈이 나에게는 어떤 의미일까요?'),
  (484, (SELECT id FROM interests WHERE code = 'ROUTINE'), '자기 전에 하루를 돌아보는 편인가요?', 3, '이불 속에서 자연스럽게 오늘을 떠올리는 편인지 바로 자는 편인지 생각해봐요.', '돌아볼 때 주로 뭐가 떠올라요?', '하루를 마무리하는 나만의 방식이 내일의 나에게 어떤 영향을 주고 있나요?'),
  (485, (SELECT id FROM interests WHERE code = 'ROUTINE'), '밤에 갑자기 마음이 무거워진 적 있나요?', 3, '낮에는 멀쩡했는데 밤이 되니 달라진 경험이 있다면 떠올려봐요.', '밤의 나와 낮의 내가 다른 사람 같다고 느낀 적 있나요?', '밤이 되면 숨겨뒀던 감정이 나오는 걸까요?'),
  (486, (SELECT id FROM interests WHERE code = 'ROUTINE'), '잠들기 전 핸드폰을 얼마나 보나요?', 3, '많이 보는 편인지, 거의 안 보는 편인지 생각해봐요.', '무의식적으로 열게 되는 앱이 있어요?', '자기 전 핸드폰 시간을 다른 걸로 바꾼다면 뭘 하고 싶어요?'),
  (487, (SELECT id FROM interests WHERE code = 'ROUTINE'), '가장 귀찮은 루틴은 무엇인가요?', 3, '그 일을 해야 하는 시간이 다가오면 몸과 마음이 어떻게 반응하나요?', '그 일을 해치웠을 때의 해방감과 미루고 있을 때의 압박감 중 무엇이 더 큰가요?', '그 귀찮은 과정을 조금이라도 즐겁게 바꾸거나 생략할 수 있는 나만의 방법이 있을까요?'),
  (488, (SELECT id FROM interests WHERE code = 'ROUTINE'), '눕고 나서 실제로 잠들기까지 얼마나 걸리나요?', 3, '불을 끄고 누운 직후, 머릿속을 채우는 가장 주된 생각이나 감정은 무엇인가요?', '잠이 오지 않아 뒤척이는 시간 동안 스마트폰을 보거나 다른 행동을 하나요?', '눈을 감고 잠을 청하는 그 고요한 시간이 나에게는 휴식인가요, 아니면 고통인가요?'),
  (489, (SELECT id FROM interests WHERE code = 'ROUTINE'), '생각할 틈 없이 ''자동''으로 나오는 내 반응이 있나요?', 3, '최근에 "또 이러고 말았네" 했던 순간과 그때의 반응을 떠올려봐요.', '그 반응이 처음 만들어진 건 언제쯤, 어떤 기억 때문이었나요?', '다음에 같은 상황이 오면 조금만 다르게 행동해볼 수 있을까요?'),
  (490, (SELECT id FROM interests WHERE code = 'ROUTINE'), '겉으론 ''응''이라고 하지만 속으론 ''싫어'' 하는 게 있나요?', 3, '마음은 거절하고 싶은데 "네"라고 대답했던 최근의 순간이 있나요?', '왜 "아니"라고 말하지 못했는지 내 속마음을 가만히 들어봐요.', '이번 주엔 아주 작은 것 하나라도 솔직하게 거절하는 연습을 해볼까요?'),
  (491, (SELECT id FROM interests WHERE code = 'ROUTINE'), '오늘 충분히 휴식했나요?', 3, '온전히 나만을 위해 쓴 시간이 얼마나 되었나요?', '여유가 부족했다면 무엇이 나의 시간을 빼앗아 갔나요?', '내일은 10분이라도 나만의 멍 때리는 시간을 확보해볼까요?'),
  (492, (SELECT id FROM interests WHERE code = 'ROUTINE'), '오늘 일과 삶 사이의 균형을 잡기 위해 노력한 점은 무엇인가요?', 3, '너무 일에만 치우치지 않게 나를 조절한 순간이 있나요?', '균형이 무너지려 할 때 나를 잡아준 생각은 무엇이었나요?', '나만의 ''균형 유지 비결''을 한 문장으로 정리해봐요.'),
  (493, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '절친을 이성에게 소개한다면 누구인가요?', 3, '그 친구의 어떤 매력을 이성에게 가장 자랑하고 싶나요?', '소개해주고 싶을 만큼 그 친구를 깊이 신뢰하고 있나요?', '두 사람이 잘 된다면 진심으로 축하해줄 수 있나요?'),
  (494, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '친한 친구가 큰 잘못을 저지르고 숨겨달라 하면 도와줄 건가요?', 3, '우정과 정의 사이에서 갈등하는 내 마음을 가만히 들여다봐요.', '친구를 지키고 싶은 마음과 두려운 마음 중 무엇이 더 큰가요?', '내가 생각하는 진정한 우정의 책임은 어디까지인가요?'),
  (495, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '오래된 관계와 새로운 관계 중 어디에 더 힘을 쓰나요?', 3, '최근 나의 시간과 에너지가 주로 누구에게 향했는지 돌아보세요.', '관계 속 안정감과 설렘 중 무엇이 더 우선인가요?', '왜 그쪽에 더 쏟고 있나요?'),
  (496, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '상대방의 약점을 알게 되면 가까워진 느낌인가요, 아니면 부담스러운가요?', 3, '누군가의 약점을 처음 알게 되었던 순간의 기분을 떠올려 보세요.', '그 사실이 관계를 더 단단하게 만들었나요, 아니면 더 조심스럽게 만들었나요?', '타인의 약점은 나에게 인간적인 유대인가요, 아니면 내가 감당해야 할 무게인가요?'),
  (497, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '관계에서 주고받는 것의 균형을 중요하게 생각하나요?', 3, '내가 일방적으로 더 많이 줬거나, 반대로 과한 배려를 받았던 구체적인 순간의 기분을 떠올려 보세요.', '베푸는 행위 자체에서 기쁨을 느끼는 편인가요, 아니면 내가 준 만큼 돌아오지 않을 때 서운함을 느끼는 편인가요?', '돌려받는다는 것은 구체적으로 어떤 형태인가요? 눈에 보이는 행동인가요, 아니면 보이지 않는 진심인가요?'),
  (498, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '연락을 자주 하는 편인가요?', 3, '연락의 빈도 때문에 부담을 느꼈거나, 반대로 소원함을 느꼈던 최근의 관계를 떠올려 봐요.', '나에게 연락은 관계 유지를 위한 노력인가요, 아니면 일상을 공유하고 싶은 마음인가요?', '나에게 편안한 관계는 대화가 끊이지 않는 관계인가요, 대화가 잠시 멈춰도 어색하지 않은 관계인가요?'),
  (499, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '넓고 얕은 인간 관계와 좁고 깊은 인간 관계 중 무엇을 더 선호하나요?', 3, '사람마다 인간관계를 대하는 태도가 달라요.', '새로운 사람을 알아가며 내 세상을 넓히기도 하고, 소중한 사람과 깊게 교류하며 관계를 단단히 쌓아가기도 해요.', '지금의 관계관이 만들어진 계기도 떠올려봐요.'),
  (500, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '의견이 다를 때 어떻게 대화를 풀어나가나요?', 3, '차이를 다루는 방법이 관계에 중요해요.', '친구 혹은 가족과 의견이 달랐던 상황을 떠올려보세요.', '왜 지금의 대화 방식으로 차이를 해결하게 되었을까요?'),
  (501, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '인간관계에 쏟는 에너지는 어느정도인가요?', 3, '관계에 쏟는 에너지 양은 사람마다 달라요.', '쏟는 에너지는 얼마나 많은 사람과 관계를 유지하는지를 넘어 관계의 깊이에 따라서도 달라져요.', '왜 지금 정도의 에너지를 쏟게 되었을지도 떠올려봐요.'),
  (502, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '사람들과의 관계가 가장 크게 바뀌었던 순간은 언제인가요?', 3, '사소한 사건부터 큰 변화로부터 인간관계가 바뀌곤 해요.', '한 때는 힘들었을 수 있어도 큰 성장으로 이어지기도 해요.', '지금 그 경험이 현재의 관계관에 어떤 영향을 줬을까요?'),
  (503, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '관계가 자연스럽게 멀어질 때 어떻게 행동하나요?', 3, '평생 함께할 것 같은 관계도 자연스럽게 멀어지곤 해요.', '멀어지지 않게 노력하거나 어쩔 수 없다고 생각하며 받아들이기도 해요.', '연락이 뜸해진 친구들을 떠올리면서 써봐요.'),
  (504, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '친해지고 싶은 사람이 생기면 어떻게 하나요?', 3, '새롭게 사람들을 만나다보면 친해지고 싶은 사람을 발견하곤 해요.', '친해지고 싶다는 생각이 들자마자 말을 걸기도, 친해지고 싶다는 생각만 하기도 해요.', '왜 친해지고 싶은지도 떠올리면서 써봐요.'),
  (505, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '친구들이 말하는 나는 어떤 사람인가요?', 3, '친구들과 함께하다보면 서로의 다양한 면을 알게돼요..', '친구들이 나에 대해 말할 때 자주 사용하는 표현을 떠올려봐요.', '어떤 가치관과 행동이 지금의 이미지를 만들었을까요?'),
  (506, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '나만 노력하는 것 같은 관계가 있나요?', 5, '내가 손 놓으면 끝날 것 같은 사람이 있나요?', '왜 그렇게 느끼나요?', '그래도 유지하고 싶은 이유가 있어요?'),
  (507, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '가족이라서 참는게 있나요?', 5, '다른 사람이었으면 어땠을까요?', '참는 게 당연하다고 생각해요?', '아니라면 나만의 건강한 해소 방법이 있나요?'),
  (508, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '오래 알았는데 멀어진 사람 있나요?', 5, '마지막으로 연락한 게 언제예요?', '먼저 연락하기엔 뭔가 애매해요?', '멀어진 게 섭섭한가요? 아니면 후련한가요?'),
  (509, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '부모님한테 인정받고 싶은 마음이 아직 있나요?', 5, '어떤 말을 들으면 인정받았다고 느낄까요?', '왜 부모님께 인정받고 싶은 마음이 계속 남을까요?', '인정받고 싶은 마음의 크기는 어떻게 변하고 있나요?'),
  (510, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '실망해도 기회를 또 주는 편인가요?', 5, '몇 번까지 줘본 적 있나요?', '믿고 싶인가요, 끊기 싫어서인가요?', '기회를 더 줘서 후회됐거나 만족했던 경험이 있나요?'),
  (511, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '다수 의견이랑 다를 때 말하는 편인가요?', 5, '다른 사람과 다른 의견을 내는 건 쉬운 일이 아니에요.', '다수가 말하지만 내 의견은 다를 때 어떤 생각을 하나요?', '말했을 때 반응은 어땠나요?'),
  (512, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '상황이 사람을 바꾼다고 느낀 적 있나요?', 3, '나이가 들면서 상황도 다양하게 바뀌곤 해요.', '주변과 나를 되돌아 볼까요?', '사람이 바뀌는 건 상황 때문인가요, 결국 개인의 선택인가요?'),
  (513, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '외로움이 무서워서 관계를 유지한 적 있나요?', 5, '안 맞는 걸 알아도 관계를 붙잡게 될 때가 있죠.', '그 이유가 외로움이었던 적이 있나요?', '그 때 진짜 무서웠던 건 혼자가 되는 것이었나요, 아니면 혼자인 내가 초라해 보이는 것이었나요?'),
  (514, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '요즘 가장 신경쓰이는 사람이 있나요?', 3, '자꾸 떠오르거나 마음에 걸리는 사람이 있을 거예요.', '그 신경 씀이 걱정인지, 호감인지, 불편함인지 구분해봐요.', '그 마음을 어떻게 하고 싶은지 한 줄로 적어봐요.'),
  (515, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '최근에 가장 기분 좋게 이야기를 나눈 사람은 누구인가요?', 3, '대화 후 기분이 좋아진 사람이 떠오를 거예요.', '그 대화에서 어떤 부분이 기분을 좋게 만들었나요?', '그 사람과 비슷한 대화를 다시 만들려면 뭐가 필요할까요?'),
  (516, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '지금 가장 보고 싶은 존재는 뭔가요?', 4, '사람이든 반려동물이든, 떠올리면 마음이 말랑해지는 존재가 있을 거예요.', '보고 싶은 이유가 그리움인지, 위로인지, 안정감인지 살펴봐요.', '지금 그 존재에게 한마디 건넨다면 뭐라고 할 건가요?'),
  (517, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '나 자신과 했던 약속 중 아직 유효한 게 있나요?', 3, '"앞으로 이렇게 하자"라고 나에게 다짐했던 게 떠오르나요?', '그 약속을 지키지 못해 미안한 마음이 들진 않나요?', '오늘부터 다시 시작할 수 있는 아주 작은 행동 하나는 뭘까요?'),
  (518, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '오늘 누군가에게 "고마워"라고 말하고 싶었나요?', 3, '생각만 해도 마음이 따뜻해지는 고마운 사람이 있었나요?', '그 사람의 어떤 점이 나의 하루를 빛나게 해주었나요?', '그 고마운 마음을 전할 수 있는 가장 나다운 방법은?'),
  (519, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '나의 말이나 행동이 타인에게 기분 좋은 울림을 줬나요?', 3, '내 작은 배려에 상대방이 환하게 웃어준 순간이 있나요?', '그 반응을 보며 나의 마음은 또 어떻게 일렁였나요?', '내가 가진 선한 영향력은 어떤 모습인지 생각해보세요.'),
  (520, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '나는 사람들에게 마음을 얼마나 열어두고 있나요?', 3, '내 마음의 문이 지금 몇 %쯤 열려 있는지 숫자로 살짝 적어봐요.', '마음을 열지 못하게 꼭 붙잡고 있는 두려움이나 옛 기억이 있나요?', '이번 주에 누군가에게 평소보다 조금 더 솔직한 이야기를 해볼까요?'),
  (521, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '누군가와 ''진짜 함께 있다''는 건 어떤 느낌일까요?', 3, '"이 사람이 정말 내 곁에 있구나" 싶었던 따뜻한 순간을 떠올려봐요.', '나는 소중한 사람과 함께할 때 정말 ''그 순간''에 온전히 머무나요?', '이번 주엔 소중한 사람과 딱 10분만 폰을 내려두고 눈을 맞춰봐요.'),
  (522, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '사람들과 더 가까워지는 걸 방해하는 게 있다면요?', 3, '더 친해지고 싶었지만 왠지 그러지 못했던 경험이 있나요?', '관계가 깊어지려 할 때 나도 모르게 거리를 두는 습관이 있나요?', '그 벽을 다 허물지 않아도 괜찮아요. 이번에 한 가지만 다르게 해볼까요?'),
  (523, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '사람들과 이야기할 때 나는 사실 무엇을 원하나요?', 3, '최근에 좋았던 대화와 아쉬웠던 대화의 차이를 곰곰이 떠올려봐요.', '좋았던 대화에서 내가 진짜 얻고 싶었던 위로나 인정은 뭐였나요?', '다음에 대화할 땐 "나는 이런 게 필요해"라고 내 마음을 먼저 알아줘요.'),
  (524, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '말을 건네고 싶었지만 꾹 참은 사람이 있나요?', 3, '한 걸음 다가가려다 망설이며 멈춰 선 순간이 있었나요?', '그 망설임 뒤에 숨어있던 진짜 이유는 무엇이었을까요?', '용기 내어 먼저 손을 내밀었다면 어떤 말을 했을까요?'),
  (525, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '오늘 누군가에게 미안한 마음이 가볍게 스쳤나요?', 3, '사소한 오해나 말실수로 마음에 걸리는 사람이 있나요?', '미안함의 이유가 내 행동 때문이었는지, 당시 상황 때문이었나요?', '그 미안함을 털어내기 위해 건네고 싶은 한 문장은?'),
  (526, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '오늘 관계 때문에 마음이 조금 무거웠던 적이 있나요?', 3, '누군가와 함께 있을 때 왠지 불편하거나 조심스러웠나요?', '그 불편함이 상대에게서 온 건가요, 내 안의 부담감인가요?', '그 마음을 편안하게 만들기 위해 내가 할 수 있는 작은 노력은?'),
  (527, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '지금 내 곁에서 가장 소중하게 느껴지는 사람은?', 3, '떠올리는 것만으로도 든든한 버팀목이 되는 이름이 있나요?', '그 사람이 왜 나에게 그토록 소중한 존재가 되었을까요?', '오늘 그 사람에게 감사의 메시지를 하나 보내보는 건 어떨까요?'),
  (528, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '오늘 누군가와 진심이 닿는 대화를 나눴나요?', 3, '겉도는 인사 말고, 마음과 마음이 오간 대화가 있었나요?', '그 대화가 끝난 후 내 마음엔 어떤 여운이 남았나요?', '그 사람에게 아직 다 하지 못한 말이 있다면 적어보세요.'),
  (529, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '상대의 감정을 예민하게 읽어낸 순간이 있었나요?', 3, '누군가의 미세한 떨림이나 표정 변화를 눈치챘나요?', '그때 나는 그 마음을 어떻게 보듬어주었나요?', '타인의 마음을 잘 느끼는 것이 나에게는 어떤 의미인가요?'),
  (530, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '오늘 내가 먼저 용기 내어 다가간 적이 있나요?', 3, '서먹한 분위기를 깨고 먼저 말을 걸거나 손을 내밀었나요?', '그렇게 행동하게 만든 나의 예쁜 동기는 무엇이었을까요?', '다가간 후에 느꼈던 안도감이나 기쁨을 기억해보세요.'),
  (531, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '오늘 내가 누군가를 소리 내어 웃게 만들었나요?', 3, '나의 농담이나 행동에 상대가 빵 터졌던 순간이 있나요?', '타인을 웃게 만드는 나의 능력은 내 기분을 어떻게 바꾸나요?', '누군가의 웃음소리가 나에게 주는 에너지를 느껴보세요.'),
  (532, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '가장 가까운 사람에게 꼭 전하고 싶은 말이 있나요?', 3, '마음 깊은 곳에 담아두고 아직 꺼내지 못한 말이 있나요?', '왜 그 말을 꺼내기가 그토록 어려웠을까요?', '부담 없이, 아주 담백하게 전할 수 있는 한마디를 적어봐요.'),
  (533, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '이번 주, 존재만으로도 감사했던 사람이 있었나요?', 3, '힘든 시간을 같이 견뎌준 고마운 인연을 떠올려보세요.', '그 감사를 표현했나요, 아니면 마음속으로만 간직했나요?', '전하지 못한 진심이 있다면 여기서 연습 삼아 적어볼까요?'),
  (534, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '"조금 더 다정하게 말할걸" 하고 후회되는 순간은 언제인가요?', 3, '내 감정이 앞서서 말투가 조금 날카로웠던 적이 있나요?', '그때 사실 내 마음은 어떤 상태였기에 그랬을까요?', '다음에 비슷한 상황이 오면 어떤 온도로 말하고 싶나요?'),
  (535, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '지금 이 순간, 문득 생각나서 연락하고 싶은 사람은 누구인가요?', 3, '갑자기 마음 한구석이 간지러워지며 떠오르는 이름은?', '그 사람에게 전하고 싶은 마음은 그리움인가요, 반가움인가요?', '고민하지 말고 짧은 안부 인사 하나 건네보는 건 어떨까요?'),
  (536, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '이번 주, 소중한 사람과 함께한 기억을 한 줄로 적어볼까요?', 3, '한 주 동안 사람들과 나눈 시간 중 가장 예쁜 장면은?', '그 기억이 나에게 특별한 보석처럼 남은 이유는 무엇일까요?', '그 사람과 또 어떤 추억을 쌓아가고 싶은지 상상해봐요.'),
  (537, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '주변인 중 누구의 죽음이 가장 괴로울 것 같은가요?', 5, '무겁지만 솔직하게 떠올려봐요. 없는 상황을 떠올려도 힘든 사람이 있나요?', '그 사람이 떠오른 이유는 뭔가요?', '그 존재가 나에게 어떤 의미인지 알려주는 것 같나요?'),
  (538, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '다시 잡고 싶은 인연이 있나요?', 3, '그 사람과 멀어지게 된 결정적인 계기가 무엇이었나요?', '지금 그 사람의 소식을 들으면 마음이 어떨 것 같나요?', '그 인연을 다시 잡는다면 가장 먼저 하고 싶은 말은 무엇인가요?'),
  (539, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '인생에 가장 영향력 있던 사람은 누구인가요?', 3, '그 사람이 나의 어떤 생각이나 행동을 가장 크게 바꿔 놓았나요?', '그 사람과 함께할 때 나는 어떤 사람이 되었다고 느꼈나요?', '지금의 나에게 그 사람의 흔적은 어떻게 남아있나요?'),
  (540, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '절대 잊지 못할 나쁜 사람이 있나요?', 3, '그 사람이 나에게 준 상처가 구체적으로 무엇이었나요?', '그 일 이후로 사람을 대하는 나만의 기준이 달라졌나요?', '이제는 그 사람으로부터 마음이 얼마나 자유로워졌다고 느끼나요?');
INSERT INTO daily_questions (id, interest_id, question_text, question_level, empathy_guide, hint_guide, leading_question_guide)
VALUES
  (541, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '다시 돌아가서 싸우고 싶은 순간이 있나요?', 3, '그때 왜 제때 목소리를 내지 못했는지 기억나나요?', '다시 그 상황에 선다면 어떤 말을 가장 먼저 내뱉고 싶나요?', '그때의 나를 지금의 내가 안아준다면 무엇이라 말하고 싶나요?'),
  (542, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '남이 말해줘서 알게 된 나의 특징은 무엇인가요?', 3, '그 말을 들었을 때 의외라고 느꼈나요, 아니면 수긍했나요?', '타인의 시선과 내가 아는 나의 모습 중 어느 쪽이 더 편한가요?', '그 발견 이후로 나의 태도나 행동에 변화를 준 적이 있나요?'),
  (543, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '주변 사람을 덕질해 본 적이 있나요?', 3, '그 사람의 어떤 면이 나를 가장 매료시켰나요?', '그를 지켜보는 것만으로도 내 일상이 즐거웠던 기억이 있나요?', '누군가를 동경했던 경험이 나에게 어떤 영감을 주었나요?'),
  (544, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '우정이란 어떤 의미인가요?', 3, '친구를 생각하면 떠오르는 단어나 장면이 있나요?', '나에게 우정은 필수인가요, 선택인가요?', '우정에 대한 나의 정의가 경험을 통해 바뀐 적 있나요?'),
  (545, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '지금 당장 죽는다면 누구에게 어떤 걸 말하지 않은 것을 후회할 것 같나요? ', 5, '편하게 떠오르는 사람과 말을 생각해봐요.', '왜 아직 그 말을 하지 못했나요?', '그 말을 전한다면 관계가 어떻게 달라질까요?'),
  (546, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '우정에서 무엇을 가장 중요하게 생각하나요?', 3, '신뢰, 재미, 솔직함, 시간 등 떠오르는 것이요.', '그 가치가 중요해진 계기가 있나요?', '나는 그 기준을 친구에게 잘 지키고 있나요?'),
  (547, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '어머니와의 관계에 대해 어떻게 생각하나요?', 5, '지금의 관계를 한 문장으로 표현해봐요.', '어릴 때와 지금, 관계가 달라진 부분이 있나요?', '어머니와의 관계가 나의 다른 관계에 영향을 주나요?'),
  (548, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '아버지와의 관계에 대해 어떻게 생각하나요?', 5, '지금의 관계를 한 문장으로 표현해봐요.', '아버지에게 말하지 못한 것이 있나요?', '아버지와의 관계가 나의 삶에 어떤 영향을 남겼나요?'),
  (549, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '자란 방식에 대해 바꿀 수 있다면, 무엇을 바꾸고 싶나요?', 5, '어린 시절 환경이나 교육 방식을 떠올려봐요.', '그때 바뀌었다면 지금의 나는 어떻게 달랐을까요?', '바꾸고 싶은 부분이 지금의 나를 만든 면도 있나요?'),
  (550, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '나의 가족은 얼마나 가깝고 따뜻한가요? ', 3, '가족과 함께 있을 때의 분위기를 떠올려봐요.', '그 온도가 만족스러운가요?', '가족의 따뜻함이 나의 관계 방식에 어떤 영향을 줬나요?'),
  (551, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '친한 친구가 된다면 그 사람이 알아야 할 중요한 사항은 무엇인가요?', 3, '나와 가까워지려면 꼭 알아야 할 것을 떠올려봐요.', '그걸 미리 말하고 싶은 이유는 뭔가요?', '그 사항이 나를 이해하는 열쇠인 것 같나요?'),
  (552, (SELECT id FROM interests WHERE code = 'RELATIONSHIP'), '어린 시절은 대부분의 다른 사람들보다 행복했다고 느끼나요?', 5, '어린 시절의 전반적인 기억을 떠올려봐요.', '행복했든 아니든, 그렇게 느끼는 기준은 뭔가요?', '어린 시절의 경험이 지금의 나를 얼마나 만들었나요?'),
  (553, (SELECT id FROM interests WHERE code = 'LOVE'), '연애할 때 혼자만의 시간도 중요한가요?', 3, '혼자 있는 시간이 필요하기도 해요.', '혼자만의 시간에 에너지가 생기는지 생각해보세요.', '혼자만의 시간을 충분히 보내고 나면 상대방에게 더 다정한 마음이 생기나요?'),
  (554, (SELECT id FROM interests WHERE code = 'LOVE'), '사랑과 좋아함의 차이는 무엇인가요?', 3, '사랑과 좋아하는 감정은 다르지만 그 기준은 사람마다 달라요.', '좋아하는 감정에서 사랑이라는 감정으로 바뀐 순간을 떠올려보세요.', '그 차이는 무엇인가요?'),
  (555, (SELECT id FROM interests WHERE code = 'LOVE'), '싸운 뒤 바로 풀려고 하는 편인가요 아니면 시간을 두고 대화하는 편인가요?', 3, '최근의 다툼에서 즉각적인 대화를 원했는지, 혹은 혼자만의 시간이 필요했는지 떠올려 보세요.', '길어지는 오해가 두려운가요, 서툰 말이 줄 상처가 두려운가요?', '상대와 갈등을 푸는 방식이 다를 때 어떻게 풀어나가지도 생각해봐요.'),
  (556, (SELECT id FROM interests WHERE code = 'LOVE'), '사랑에 빠지는 것과 사랑을 유지하는 것 중 무엇이 더 어려운가요?', 3, '관계의 단계마다 다른 노력이 필요해요.', '설렘과 책임감을 비교해보세요.', '어느 쪽에서 더 힘들었나요?'),
  (557, (SELECT id FROM interests WHERE code = 'LOVE'), '좋아할 때 숨기기 어려운 건 무엇인가요?', 3, '아무리 숨겨도 눈치 빠른 사람은 알아채죠. 뭘로 들킬 것 같나요?', '좋아하는 사람 앞에서 나도 모르게 하는 행동을 떠올려보세요.', '그게 들킬까봐 신경 쓰이나요, 들켰으면 좋겠나요?'),
  (558, (SELECT id FROM interests WHERE code = 'LOVE'), '좋아하는 사람에게 먼저 연락하나요, 기다리나요?', 3, '먼저 연락하는 용기가 관계 주도성을 보여줘요.', '문자 보내기 전 고민했던 시간을 떠올려보세요.', '왜 기다렸나요? 왜 먼저 했나요?'),
  (559, (SELECT id FROM interests WHERE code = 'LOVE'), '사랑받고 있다고 느끼는 순간은 언제인가요?', 3, '사랑에 대한 가치관은 내가 어떻게 사랑을 확인하는지를 통해 알아볼 수 있어요.', '가장 사랑받는다고 느낀 순간을 떠올려보세요.', '그게 없으면 사랑받는 게 아닌 것 같나요?'),
  (560, (SELECT id FROM interests WHERE code = 'LOVE'), '이별 후 얼마나 있어야 새 연애가 가능한가요?', 3, '이별 후 회복 시간은 사람마다 달라요.', '이별 후 혼자인 시간이 필요하는가요?', '준비가 됐다는 걸 어떻게 아나요?'),
  (561, (SELECT id FROM interests WHERE code = 'LOVE'), '전 애인과 친구가 될 수 있나요?', 3, '이별 후 관계가 감정 정리 방식을 보여줘요.', '전 애인과의 현재 관계를 떠올려보세요.', '진짜 친구인가요?'),
  (562, (SELECT id FROM interests WHERE code = 'LOVE'), '연인에게 절대 져줄 수 없는 것이 있나요?', 3, '양보 못 하는 것이 자존심의 핵심을 보여줘요.', '연애에서 꺾이지 않았던 것을 떠올려보세요.', '왜 거기선 못 지나요?'),
  (563, (SELECT id FROM interests WHERE code = 'LOVE'), '끌리는 사람과 좋은 사람 중 누구를 선택하나요?', 3, '설렘과 안정 중 우선순위가 연애관을 보여줘요.', '두 유형을 각각 떠올려보세요.', '최근의 연애를 떠올려보세요.'),
  (564, (SELECT id FROM interests WHERE code = 'LOVE'), '이상형과 실제 사귄 사람이 같나요?', 3, '만나고 나니 이상형이 바뀌기도 하고, 이상형과 전혀 다른 사람을 만나기도 하죠.', '이상형과 전 연인들을 떠올려보세요.', '이상형이었나요?'),
  (565, (SELECT id FROM interests WHERE code = 'LOVE'), '이상형의 조건 중 협상 가능한 것과 불가능한 것은 무엇인가요?', 3, '타협할 수 있는 조건과 타협할 수 없는 조건을 알아두는 것은 중요해요.', '좋아해도 깨던 점과 좋아하면 안 보이는 조건을 떠올려보세요.', '어디까지 양보할 수 있나요?'),
  (566, (SELECT id FROM interests WHERE code = 'LOVE'), '처음엔 별로였는데 나중에 좋아진 적 있나요?', 3, '알면 알수록 좋아지는 사람이 있고, 알수록 별로인 사람이 있어요.', '처음엔 친구였는데 어느 순간 달리 보인 사람을 떠올려보세요.', '뭘 알게되고나서 달라졌나요?'),
  (567, (SELECT id FROM interests WHERE code = 'LOVE'), '이번 주, 마음이 몽글몽글한 순간은 언제였나요?', 3, '예상치 못한 다정함이나 기분 좋은 설렘이 스친 적 있나요?', '그때 어떤 풍경 속에 있었고, 공기는 어떤 느낌이었나요?', '그런 따스한 온기를 다시 느끼기 위해 할 수 있는 건 뭘까요?'),
  (568, (SELECT id FROM interests WHERE code = 'LOVE'), '지금까지 만난 사람들의 공통점은 무엇인가요?', 3, '만난 사람들을 떠올려보면 공통점이 보여요.', '그 공통점을 내가 좋아하는 이유는 무엇일까요?', '공통점이 없다면 다름에도 그 사람들을 좋아했던 이유는 무엇일까요?'),
  (569, (SELECT id FROM interests WHERE code = 'LOVE'), '인생에서 사랑과 애정은 어떤 의미인가요?', 3, '누군가에게 조건 없이 마음을 쏟거나 듬뿍 받았던 따뜻한 순간을 떠올려 봐요.', '그 애정이 나를 더 나은 사람으로 만들었나요, 아니면 지친 마음을 쉬게 해주었나요?', '사랑이 주는 힘을 믿는다면, 오늘 내 주변에 그 따스함을 어떻게 나누고 싶나요?'),
  (570, (SELECT id FROM interests WHERE code = 'LOVE'), '본인의 이상형 중 특이한 조건이 있나요?', 3, '그 조건에 강하게 끌리게 된 특별한 계기가 있었나요?', '남들은 사소하다 할 그 점이 왜 나에겐 결정적인 조건인가요?', '그 조건을 충족하는 사람을 만날 때 내 마음은 어떻게 반응하나요?'),
  (571, (SELECT id FROM interests WHERE code = 'LOVE'), '데이트 중 가장 창피했던 일은 무엇인가요?', 3, '상대 앞에서 귀여운 실수를 했던 그날의 장면을 떠올려 봐요.', '당황한 나를 보며 상대방은 어떤 표정을 지어주었나요?', '지금 생각해보니 그 서툰 모습조차 소중한 추억인가요?'),
  (572, (SELECT id FROM interests WHERE code = 'LOVE'), '살면서 가장 설레었던 추억은 무엇인가요?', 3, '그때의 공기, 소리, 주변 분위기가 구체적으로 기억나나요?', '심장이 내려앉는 듯한 그 느낌이 얼마나 오랫동안 지속되었나요?', '그 설렘의 기억이 지금 나의 사랑을 정의하는 기준이 되었나요?'),
  (573, (SELECT id FROM interests WHERE code = 'LOVE'), '가장 좋아했던 사람은 누구인가요?', 3, '그 대상에게 나의 에너지와 시간을 아낌없이 쏟았던 이유는 무엇인가요?', '그 대상을 좋아하며 느꼈던 가장 큰 희열의 순간은 언제였나요?', '누군가를 조건 없이 사랑해본 경험이 나를 어떻게 성장시켰나요?'),
  (574, (SELECT id FROM interests WHERE code = 'VALUES'), '남의 시선을 얼마나 의식하나요?', 3, '타인의 눈이 얼마나 내 결정을 흔드는지 보여줘요.', '"남들이 뭐라 할까" 생각했던 순간을 떠올려보세요.', '100% 익명이 보장되면 뭐가 달라질지 생각해봐요.'),
  (575, (SELECT id FROM interests WHERE code = 'VALUES'), '거절을 잘하는 편인가요?', 3, '모두 거절을 해야할 때가 찾아와요.', '"싫은데 알겠다고 한" 최근 상황이 있었나요?', '받아들이기 어려운 부탁에 어떻게 대응하고 싶은지도 떠올려봐요.'),
  (576, (SELECT id FROM interests WHERE code = 'VALUES'), '포기가 빠른 편인가요, 늦은 편인가요?', 3, '최선을 다하더라도 포기해야할 때가 와요.', '최근에 접은 것과 안 접은 것을 떠올려보세요.', '그 타이밍이 맞았나요?'),
  (577, (SELECT id FROM interests WHERE code = 'VALUES'), '내 인생에서 가장 비싸게 얻은 깨달음은 무엇인가요?', 3, '돈, 시간, 마음 중 뭘 가장 크게 썼나요?', '크게 잃고 나서 배운 것을 떠올려보세요.', '다시 돌아가더라도 그 값을 치르고 싶나요?'),
  (578, (SELECT id FROM interests WHERE code = 'VALUES'), '나를 싫어하는 순간이 있나요?', 5, '그 순간 싫어하는 건 ''나''인가요, ''그 행동''인가요?', '스스로가 한심하게 느껴졌던 순간을 떠올려보세요.', '그 순간마다 어떻게 행동하나요?'),
  (579, (SELECT id FROM interests WHERE code = 'VALUES'), '나의 생각과 감정 중 뭘 더 믿나요?', 3, '머리와 마음이 다른 말을 할 때가 있죠.', '이성적 판단과 감성적 판단 중 어떤 것이 더 옳다고 정의하기는 어려워요.', '어느 쪽을 더 따랐나요? 그리고 어느 쪽이 더 맞았나요?'),
  (580, (SELECT id FROM interests WHERE code = 'VALUES'), '바꾸고 싶은 나의 모습이 있나요?', 5, '진짜 바꾸고 싶은 건가요, 남들이 바꾸라고 해서인가요?', '"이것만 달랐으면" 하고 생각하는 것을 떠올려보세요.', '왜 아직 안 바꿨나요? 못 한 건가요, 안 한 건가요?'),
  (581, (SELECT id FROM interests WHERE code = 'VALUES'), '내가 틀렸다는 걸 인정하기 어려운 주제가 있나요?', 5, '절대 안 지는 싸움이 있다면, 거기에 자존심이 묶여 있는 거예요.', '유난히 마음을 많이 쓰는 논쟁들을 떠올려보세요.', '정치, 연애관, 일하는 방식 등 다양한 분야 중 어떤 것일까요?'),
  (582, (SELECT id FROM interests WHERE code = 'VALUES'), '내 한계를 인정하는 게 쉬운가요, 어려운가요?', 3, '한계를 인정했던 순간을 떠올려보세요.', '한계를 인정하는 것을 패배와 해방 중 어떤 것이라고 생각하나요?', '한계를 인정했을 때 감정도 떠올려봐요.'),
  (583, (SELECT id FROM interests WHERE code = 'VALUES'), '편안함이 성장을 막고 있다고 느낀 적 있나요?', 3, '이불 밖은 위험해... 인생도 그런가요?', '편안함은 정말 좋지만 도전을 망설이게 하는 요인으로 작용하기도 해요.', '편안함이 회피였는던 경험을 생각해봐요.'),
  (584, (SELECT id FROM interests WHERE code = 'VALUES'), '삶에서 놓치고 있는 게 있다면 뭔가요?', 5, '바쁘게 살다 보면 중요한 것들도 뒷전이 되곤 해요.', '나중에 해야지라고 생각하면서 미루고 있는 것이 있나요?', '왜 그걸 후순위에 두고 다른 가치를 우선시하게 되었는지 생각해봐요.'),
  (585, (SELECT id FROM interests WHERE code = 'VALUES'), '스스로에게 엄격한가요, 관대한가요?', 3, '나에겐 F, 남에게는 T라는 말처럼 남과 나에게 대하는 태도는 다른 경우가 많아요.', '남들에게 대하는 나의 태도와 비교해봐요.', '현재 나의 태도가 갖는 장점과 단점에 대해서도 생각해볼까요?'),
  (586, (SELECT id FROM interests WHERE code = 'VALUES'), '언제 가장 살아있다고 느끼나요?', 3, '시간 가는 줄 모르고 집중했던 순간을 떠올려볼까요?', '그런 순간이 일상에 얼마나 있나요?', '어떤 사람과 함께 있을 때 또는 어떤 행동을 할 때였나요?'),
  (587, (SELECT id FROM interests WHERE code = 'VALUES'), '가장 간절히 원했던 것은 무엇이었나요?', 3, '없으면 안 될 것 같은 것이 있었나요?', '이루고자 어떤 일까지 해봤는지 떠올려봐요.', '결국 얻었나요? 그리고 그 과정에서 무얼 깨달았나요?'),
  (588, (SELECT id FROM interests WHERE code = 'VALUES'), '예전에 한 행동 중 아직도 부끄러운 게 있나요?', 5, '갑자기 떠올려서 이불킥하게 되는 기억, 있잖아요.', '왜 부끄럽나요?', '그때 나는 왜 그랬을까요?'),
  (589, (SELECT id FROM interests WHERE code = 'VALUES'), '과거로 돌아가고 싶은 순간이 있나요?', 3, '돌아가서 다시 하고 싶은 건가요, 그때가 그리운 건가요?', '왜 그 순간으로 돌아가고 싶은 볼까요?', '그 순간으로 돌아가면 뭘 바꾸고 싶나요?'),
  (590, (SELECT id FROM interests WHERE code = 'VALUES'), '과거에 받은 상처 중 아직 안 나은 게 있나요?', 5, '수 년 전 일이어도 계속 생각나서 고통스러운 상처, 있잖아요.', '그 상처를 건드리는 건 어떤 순간인가요?', '나으려면 뭐가 필요할까요? 시간인가요, 사과인가요, 나 자신인가요?'),
  (591, (SELECT id FROM interests WHERE code = 'VALUES'), '잊고 싶은 기억이 있나요?', 3, '잊고 싶을수록 더 선명해지는 것들이 있어요.', '그 기억을 떠올릴 때마다 어떤 감정이 드나요?', '잊는 것과 받아들이는 것, 뭐가 다를까요?'),
  (592, (SELECT id FROM interests WHERE code = 'VALUES'), '좋아하는 일과 잘하는 일 중 어느 쪽을 직업으로 삼고 싶나요?', 3, '좋아하는 일을 하며 설렜던 순간과 잘하는 일을 하며 인정받았던 순간 중 어떤 일이 더 기분 좋게 남아있나요?', '직업을 선택하는 기준은 무엇이 되어야할까요?', '요즘 갖고 있는 커리어 고민도 같이 떠올려봐요.'),
  (593, (SELECT id FROM interests WHERE code = 'VALUES'), '돈과 시간 중 더 소중한 건 무엇인가요?', 2, '삶에서의 우선순위는 삶의 방향성을 결정해요.', '둘 중 하나를 선택했던 순간을 떠올려보세요.', '이런 가치관을 갖게 된 배경을 떠올려봐요.'),
  (594, (SELECT id FROM interests WHERE code = 'VALUES'), '성공은 어떤 의미인가요?', 3, '성공의 기준과 성공 이후의 감정은 사람마다 달라요.', '성공했다고 생각했던 순간을 떠올려보세요.', '앞으로 어떤 성공을 쌓아가고 싶나요?'),
  (595, (SELECT id FROM interests WHERE code = 'VALUES'), '꿈과 현실의 균형을 어떻게 맞추고 있나요?', 3, '설레게 하는 꿈을 떠올려봐요.', '현실과 꿈이 부딪칠 때, 어느 쪽을 더 지키려 하나요?', '꿈을 위해 현실을 견디나요, 현실을 위해 꿈을 조절하나요?'),
  (596, (SELECT id FROM interests WHERE code = 'VALUES'), '다수의 의견과 내 생각이 다를 때 어떻게 하나요?', 3, '모두와 의견이 엇갈렸던 상황을 떠올려봐요.', '다수와 의견이 다른 상황에서 끝까지 내 생각을 말하는 건 어려운 일이에요.', '내 생각을 끝까지 설득하나요, 다수를 이해하기 위해 노력하나요?'),
  (597, (SELECT id FROM interests WHERE code = 'VALUES'), '재능과 노력 중 무엇이 더 중요하다고 생각하나요?', 3, '"천재란 1%의 영감과 99%의 노력으로 이뤄진다."는 말을 어떻게 생각하나요?', '이 말은 노력의 중요성을 강조할 때 자주 사용되곤 했지만, 1%의 재능이 없다면 노력도 필요 없다는 말이었다는 이야기도 있어요.', '내가 생각하는 성공은 운명인지, 노력에 따른 보상인지 생각해봐요.'),
  (598, (SELECT id FROM interests WHERE code = 'VALUES'), '좋은 마음의 나쁜 결과와 나쁜 마음의 좋은 결과 중 어느 쪽이 더 나쁜가요?', 3, '좋은 의도가 문제를 일으켰던 순간, 혹은 이기적인 행동이 뜻밖에 이득을 주었던 일을 떠올려봐요.', '결과가 좋다면 과정은 덮어 둘 수 있는 걸까요?', '반대로 과정이 좋지 않다면 결과는 중요하지 않은걸까요?'),
  (599, (SELECT id FROM interests WHERE code = 'VALUES'), '모두에게 이로운 거짓말은 괜찮다고 생각하나요?', 3, '진실이 상처가 될 때, 타인을 위한 거짓말을 하곤 해요.', '하지만 착한 뜻이라도 거짓말 자체가 나쁘다는 의견도 많아요.', '이런 갈림길 속에서 고민했던 순간들을 떠올려봐요.'),
  (600, (SELECT id FROM interests WHERE code = 'VALUES'), '가장 이기고 싶을 땐 언제인가요?', 3, '승부욕이 발동하는 순간이 진짜 욕망을 보여줘요.', '꼭 이겨야겠다고 느낀 순간을 떠올려보세요.', '누구와, 무엇을, 왜 이기고 싶었나요?'),
  (601, (SELECT id FROM interests WHERE code = 'VALUES'), '내게 가장 위선적인 부분이 무엇인가요?', 5, '''이러면 안 되는데'' 하면서도 하는 것을 떠올려보세요.', '그 위선을 누가 알면 어떤 기분일 것 같나요?', '왜 그걸 고치지 못하고 있나요?'),
  (602, (SELECT id FROM interests WHERE code = 'VALUES'), '죽기 전에 꼭 해보고 싶은 건 뭔가요?', 4, '망설여져도 꼭 하고 싶은 일을 떠올려봐요.', '왜 꼭 하고 싶다는 생각을 하게 됐나요?', '그런데 왜 아직 하지 못했나요?'),
  (603, (SELECT id FROM interests WHERE code = 'VALUES'), 'TV에 나온다면 어떤 일로 나오게 될 것 같나요?', 3, '지금까지 해 온 일, 앞으로 하고 싶은 일을 떠올려보세요.', '후회되는 일, 만족스러운 일 또는 기대되는 일이 있나요?', '뉴스든 예능이든 다큐든 떠오르는 장면을 상상해보세요.'),
  (604, (SELECT id FROM interests WHERE code = 'VALUES'), '최근에 가장 기억에 남는 뉴스는 뭔가요?', 3, '최근에 본 사회 이슈, 정치, 경제, 연예, 범죄 등 떠올려보세요.', '그 뉴스를 보고 어떤 감정이 들었나요?', '그 뉴스를 보고 어떤 감정이 들었나요?'),
  (605, (SELECT id FROM interests WHERE code = 'VALUES'), '가장 자주 합리화하는 행동은 뭔가요?', 3, '반복적으로 잘못해도 어쩔 수 없었어, 이번만 등의 말로 합리화해 온 일이 있을 거예요.', '왜 유독 그 행동에 대해서 합리화하게 되나요?', '어떻게 합리화해왔는지도 떠올려봐요.'),
  (606, (SELECT id FROM interests WHERE code = 'VALUES'), '내가 생각하는 나와 남이 보는 나, 뭐가 다른가요?', 3, '의외라는 말 들은 적 있나요?', '오해라고 느꼈을 수도, 들킨 느낌이었을 수도 있어요.', '그 차이는 어디에서 나올까요?'),
  (607, (SELECT id FROM interests WHERE code = 'VALUES'), '어떤 상황에서 가장 초라해지나요?', 5, '괜히 주눅 드는 순간이 있잖아요.', '비교될 때, 무시당할 때, 준비 안 됐을 때...', '그 순간 제일 신경 쓰이는 게 뭔가요?'),
  (608, (SELECT id FROM interests WHERE code = 'VALUES'), '채워지지 않는 결핍이 있나요?', 5, '뭔가 늘 허전한 구석이 있나요?', '사랑, 인정, 안정감, 소속감... 뭐가 떠오르나요?', '그 결핍은 어디에서 비롯됐을까요?'),
  (609, (SELECT id FROM interests WHERE code = 'VALUES'), '회피하고 있는 게 있나요?', 5, '자꾸 미루거나 안 보려고 하는 게 있지 않나요?', '회피하는 것들의 공통점을 떠올려봐요.', '피하는 이유를 알고 있나요?'),
  (610, (SELECT id FROM interests WHERE code = 'VALUES'), '가장 최근에 생각이 바뀐 주제가 있나요?', 3, '예전엔 당연했는데 요즘 다르게 보이는 게 있나요.', '누군가 때문일 수도, 경험 때문일 수도 있죠.', '생각의 변화와 함께 달라진 점이 있나요?'),
  (611, (SELECT id FROM interests WHERE code = 'VALUES'), '사람은 변할 수 있다고 생각하나요?', 3, '바뀐 사람을 본 적이 있나요?', '사람이 바뀐 걸까요 아니면 사람은 그대로지만 바라보는 방식 또는 표현하는 방식이 바뀐걸까요?', '사람이 바뀐다는 게 좋은가요 아니면 아쉬운가요?'),
  (612, (SELECT id FROM interests WHERE code = 'VALUES'), '절대 바뀌지 않을 것 같은 생각이 있나요?', 3, '오래 지켜온 신념 같은 게 있을 수 있죠.', '왜 이렇게 확고한 믿음을 갖게 된 건지 떠올려봐요.', '이 가치관이 나를 어떻게 바꾸고 있나요?'),
  (613, (SELECT id FROM interests WHERE code = 'VALUES'), '예전엔 중요했는데 지금은 아닌 게 있나요?', 3, '가을방학이라는 노래처럼, 예전엔 너무 소중했던 것들도 이젠 소중히 여겼던 기억조차 희미해지곤 하죠.', '그게 뭐였는지 떠올려볼까요? 계절, 색깔 또는 어떤 사람일 수 있어요.', '덜 중요해진 게 아쉬운가요?'),
  (614, (SELECT id FROM interests WHERE code = 'VALUES'), '절대 되고 싶지 않은 사람의 모습이 있나요?', 3, '주변 사람이나 과거의 나와 같이 되고 싶지 않은 모습이 있을거예요.', '왜 그게 그렇게 싫은가요?', '그렇게 되지 않기 위해 어떤 노력을 하고 있나요?'),
  (615, (SELECT id FROM interests WHERE code = 'VALUES'), '통제할 수 없는 상황에서 어떻게 하나요?', 3, '나이가 들면서 통제 불가능한 일들이 점점 늘어나죠.', '그때마다 어떻게든 해보려 하나요, 놓아버리나요?', '통제가 어려운 상황에서 내가 느끼는 감정도 떠올려봐요.'),
  (616, (SELECT id FROM interests WHERE code = 'VALUES'), '자존심 때문에 놓친 게 있나요?', 3, '조금만 자존심을 굽혔다면 달랐을 것 같은게 있나요?', '자존심을 지켰더라도 계속 아쉬움이 남는 일을 떠올려보세요.', '그때로 돌아간다면 자존심을 굽힐 것 같나요?'),
  (617, (SELECT id FROM interests WHERE code = 'VALUES'), '과정이 나빠도 결과가 좋으면 괜찮나요?', 3, '과정이 좋다고 결과가 꼭 좋지만은 않아요.', '결과는 좋았는데 찝찝했던 적도 있을 거예요.', '과정과 결과 중 어떤 것이 더 중요하다고 생각하는지 떠올려봐요.'),
  (618, (SELECT id FROM interests WHERE code = 'VALUES'), '나이 들면서 보수적으로 변했다고 느끼나요?', 3, '나이가 들면서 경험에 따라 성향이 변화하곤 해요.', '도전에 대한 나의 생각이 어떻게 변화했는지 떠올려봐요.', '조심스러워졌나요 아니면 더 새로움을 추구하고자 노력하고 있나요?'),
  (619, (SELECT id FROM interests WHERE code = 'VALUES'), '확신이 무너진 경험이 있나요?', 3, '믿었던 게 흔들린 적 있나요?', '사람, 생각, 또는 나 자신 중 어떤 것에 대한 확신이 무너졌었나요?', '그 이후로 어떻게 바뀌었는지도 떠올려봐요.'),
  (620, (SELECT id FROM interests WHERE code = 'VALUES'), '나와 가장 닮은 영화, 책, 드라마 속 인물은 누구인가요?', 3, '영화, 책, 드라마, 애니 등 다양한 창작물을 보다보면 나와 닮은 등장인물을 보게 될 때가 있어요.', '그 캐릭터와 왜 닮았다고 생각했는지 생각해봐요.', '닮은 부분을 좋아하나요, 아니면 싫어하나요?');
INSERT INTO daily_questions (id, interest_id, question_text, question_level, empathy_guide, hint_guide, leading_question_guide)
VALUES
  (621, (SELECT id FROM interests WHERE code = 'VALUES'), '어떤 할머니/할아버지가 되고 싶나요?', 3, '일상 속에서 마주치는 노인 분들을 보며 나도 저렇게 나이들고 싶다는 생각을 해본 적 있나요?', '10년, 20년을 넘어서 먼 미래의 내가 어떤 삶을 살아가고 싶은지 떠올려봐요.', '그런 사람이 되기 위해서는 어떤 노력이 필요할까요?'),
  (622, (SELECT id FROM interests WHERE code = 'VALUES'), '요즘 내 인생에서 과감히 덜어내기로 한 것은 무엇인가요?', 3, '더 이상 짊어지고 가지 않기로 마음먹은 생각이나 관계는?', '그것을 내려놓기까지 나 자신과 어떤 대화를 나눴나요?', '비워진 자리에 새롭게 채우고 싶은 기분 좋은 에너지는?'),
  (623, (SELECT id FROM interests WHERE code = 'VALUES'), '돌아보니 칭찬해주고 싶은 오늘의 선택은 무엇인가요?', 3, '크기에 상관없이 내가 내린 결정 중 가장 훌륭했던 건?', '그때 나는 어떤 가치를 기준으로 그 선택을 내렸나요?', '그 결정 덕분에 오늘 하루가 얼마나 더 근사해졌나요?'),
  (624, (SELECT id FROM interests WHERE code = 'VALUES'), '이번 주가 나에게 조용히 건네준 교훈이 있나요?', 3, '일련의 사건들을 통해 새롭게 깨달은 삶의 진리는?', '예전의 나라면 그냥 지나쳤을 일들에서 무엇을 배웠나요?', '다음 주를 더 멋지게 살아가게 할 나만의 지침은?'),
  (625, (SELECT id FROM interests WHERE code = 'VALUES'), '요즘 예전보다 덜 흔들리는 나를 발견했나요?', 3, '과거의 나라면 무너졌을 상황에서 꿋꿋하게 버텨냈나요?', '나를 이렇게 단단하게 만들어준 원동력은 무엇인가요?', '성장한 나 자신에게 기분 좋은 눈인사를 건네보세요.'),
  (626, (SELECT id FROM interests WHERE code = 'VALUES'), '오늘 나를 움직이게 한 가장 큰 동력은 무엇인가요?', 3, '귀찮음을 이기고 행동하게 만든 나의 동기는 무엇인가요?', '의무감 때문이었나요, 아니면 진짜 하고 싶은 열망이었나요?', '나를 진짜 춤추게 만드는 동기가 무엇인지 정의해봐요.'),
  (627, (SELECT id FROM interests WHERE code = 'VALUES'), '시간을 되돌린다면 오늘을 어떻게 다르게 살까요?', 3, '아쉬움이 남는 장면을 한 번만 수정할 기회가 있다면요?', '그 아쉬움은 나의 선택 때문인가요, 아니면 결과 때문인가요?', '내일 똑같은 상황이 온다면 어떤 멋진 선택을 보여줄 건가요?'),
  (628, (SELECT id FROM interests WHERE code = 'VALUES'), '오늘 누구의 눈치도 보지 않고 오직 내 마음대로 정한 건 무엇인가요?', 3, '주변의 시선이나 기대에서 벗어나 주체적으로 행동했나요?', '스스로 결정했을 때의 그 짜릿한 자유로움을 기억해보세요.', '주도적인 삶을 살 때 나는 어떤 표정을 짓고 있나요?'),
  (629, (SELECT id FROM interests WHERE code = 'VALUES'), '예전에는 당연했는데 지금은 다르게 보이는 것이 있나요?', 3, '세상을 바라보는 나의 시선이나 기준이 바뀐 부분이 있나요?', '그 변화를 이끈 결정적인 사건이나 대화가 있었나요?', '달라진 가치관이 나의 앞날을 어떻게 바꿔놓을지 상상해봐요.'),
  (630, (SELECT id FROM interests WHERE code = 'VALUES'), '어제보다 나아졌다고 느낀 점은 뭔가요?', 3, '아주 미세하더라도 분명히 성장했다고 믿는 부분은?', '그 성장을 일궈낸 나의 끈기와 노력을 충분히 인정해주세요.', '나의 성장을 한 문장의 멋진 타이틀로 만들어볼까요?'),
  (631, (SELECT id FROM interests WHERE code = 'VALUES'), '지난 7일을 되돌아보면 머릿속을 스치는 단어는 무엇인가요?', 3, '지난 7일을 하나의 단어로 응축한다면 무엇인가요?', '왜 그 단어가 이번 주의 대표 얼굴이 되었을까요?', '다음 주에는 내 삶이 어떤 단어로 기억되길 바라나요?'),
  (632, (SELECT id FROM interests WHERE code = 'VALUES'), '최근 나 자신이 조금 어른이 되었다고 느낀 순간은 무엇인가요?', 3, '감정을 다스리거나 상황을 대처하는 방식이 달라졌나요?', '그 변화가 나를 더 편안하게 만드나요, 아니면 어색한가요?', '변화의 원인을 찾아보고 나만의 성장 일기를 써보세요.'),
  (633, (SELECT id FROM interests WHERE code = 'VALUES'), '오늘 나만의 소신이나 원칙을 멋지게 지켜냈나요?', 3, '유혹이나 타협의 순간에도 끝까지 지킨 나만의 선은?', '그 원칙을 지키는 것이 나에게 어떤 자부심을 주었나요?', '나를 지켜주는 이 든든한 기준들이 왜 중요한지 생각해보세요.'),
  (634, (SELECT id FROM interests WHERE code = 'VALUES'), '관계에서 내가 절대 포기할 수 없는 0순위는 무엇인가요?', 3, '사람을 사귈 때 가장 중요하게 보는 기준이 무엇인가요?', '최근 그 가치가 확인되었거나 혹은 상처받은 일이 있었나요?', '내가 추구하는 관계의 온도는 몇 도인지 생각해보세요.'),
  (635, (SELECT id FROM interests WHERE code = 'VALUES'), '지금 당장 감사하다고 말하고 싶은 단 한 가지는 무엇인가요?', 3, '너무 당연해서 잊고 살았던 나의 소중한 것들은 무엇인가요?', '그 감사의 대상이 나 자신인가요, 타인인가요, 아니면 환경인가요?', '이 감사한 마음이 나의 하루를 얼마나 풍요롭게 만드나요?'),
  (636, (SELECT id FROM interests WHERE code = 'VALUES'), '이번 주에 얻은 가장 값진 인생의 힌트는 무엇인가요?', 3, '삶의 파도를 넘으며 발견한 나만의 생존 전략은?', '이 깨달음이 앞으로 나의 선택들에 어떤 영향을 줄까요?', '나중에 꼭 다시 꺼내보고 싶은 한 줄의 지혜를 남기세요.'),
  (637, (SELECT id FROM interests WHERE code = 'VALUES'), '나를 키우는 가장 나다운 성장 방식은 무엇인가요?', 3, '나는 주로 경험을 통해 배우나요, 아니면 사색을 통해 배우나요?', '실패조차 배움으로 바꾸는 나만의 특별한 능력을 믿어보세요.', '더 큰 성장을 위해 내가 의식적으로 노력해야 할 부분은?'),
  (638, (SELECT id FROM interests WHERE code = 'VALUES'), '선택하지 않은 길에 대한 미련을 터는 나만의 방법은 무엇인가요?', 3, '"그때 그랬다면"이라는 생각이 들 때 어떻게 마음을 다잡나요?', '현재의 선택이 최선이었다는 증거를 하나만 찾아볼까요?', '지금의 내 선택을 더 빛나게 만들 한마디를 적어보세요.'),
  (639, (SELECT id FROM interests WHERE code = 'VALUES'), '내가 꿈꾸는 진짜 멋진 나는 어떤 사람인가요?', 3, '상상만 해도 가슴 뛰는 나의 미래 모습을 그려보세요.', '지금의 나와 그 모습 사이에 어떤 기분 좋은 차이가 있나요?', '그 모습에 한 걸음 다가가기 위해 오늘 내가 한 일은?'),
  (640, (SELECT id FROM interests WHERE code = 'VALUES'), '나의 인격이나 가치관에 가장 큰 영향을 준 인물은?', 3, '내 삶의 이정표가 되어준 사람이나 책, 영화가 있나요?', '그 영향이 지금의 나를 형성하는 데 어떤 역할을 했나요?', '앞으로 어떤 긍정적인 영향을 세상에 전하고 싶은가요?'),
  (641, (SELECT id FROM interests WHERE code = 'VALUES'), '오늘의 작은 선택이 미래의 나를 어떻게 바꿀까요?', 3, '오늘 내린 결정들이 1년 뒤의 나에게 어떤 선물이 될까요?', '그 선택의 이유를 미래의 나에게 설명해준다면요?', '미래의 내가 오늘의 나에게 보낼 고마움의 메시지를 상상해봐요.'),
  (642, (SELECT id FROM interests WHERE code = 'VALUES'), '오늘 겪은 시련이나 실수에서 찾은 뜻밖의 배움은 무엇이었나요?', 3, '실패라고 생각했던 순간 속에 숨겨진 진주는 무엇이었나요?', '이 배움이 나를 얼마나 더 단단하게 만들어줄까요?', '아픔조차 성장의 밑거름으로 쓰는 나를 응원해주세요.'),
  (643, (SELECT id FROM interests WHERE code = 'VALUES'), '이번 주, 나에 대해 새롭게 발견한 의외의 면은 무엇인가요?', 3, '"나에게 이런 모습이 있었어?" 싶었던 순간이 있나요?', '그 발견이 나를 더 입체적이고 매력적으로 느끼게 하나요?', '새로 알게 된 나를 친구에게 소개하듯 짧게 적어보세요.'),
  (644, (SELECT id FROM interests WHERE code = 'VALUES'), '무언가를 포기했던 순간, 내 마음은 어땠나요?', 3, '끝까지 붙잡지 않고 놓아주기로 했을 때 어떤 기분이었나요?', '그게 지쳐서였나요, 아니면 더 소중한 걸 지키기 위해서였나요?', '포기 뒤에 찾아온 뜻밖의 평온함을 솔직하게 기록해보세요.'),
  (645, (SELECT id FROM interests WHERE code = 'VALUES'), '"나 정말 많이 컸다"라고 스스로 감격한 순간은 언제인가요?', 3, '예전엔 못 했던 일을 담대하게 해냈던 최근의 기억은?', '성장을 가능하게 했던 나의 숨은 노력들을 칭찬해주세요.', '더 멋지게 성장할 나의 내일을 위해 어떤 약속을 할까요?'),
  (646, (SELECT id FROM interests WHERE code = 'VALUES'), '나를 한 단계 더 발전하게 만들 계획은 무엇인가요?', 3, '작지만 강력한 변화를 불러올 나만의 액션 플랜은?', '그 행동을 시작하기 주저하게 만드는 마음의 벽은 무엇인가요?', '내일 당장 해볼 수 있는 가장 쉽고 재미있는 방법은 무엇일까요?'),
  (647, (SELECT id FROM interests WHERE code = 'VALUES'), '모든 물건이 있는 집에 불이 났을 때, 소중한 가족과 애완동물을 대피시킨 후 하나의 물건만 가져나올 수 있다면 뭘 고를 것인가요?', 4, '없으면 안되는 물건은 무엇일까요?', '그 물건이 소중한 이유가 추억인지, 실용인지, 대체 불가능함인지 살펴봐요.', '그 물건과의 추억에 대해서도 떠올려봐요.'),
  (648, (SELECT id FROM interests WHERE code = 'VALUES'), '절대 장난스럽게 얘기할 수 없는 진지하거나 심각한 주제가 있나요?', 5, '누군가 가볍게 다루면 속이 불편해지는 주제가 떠오를 거예요.', '그 주제가 민감한 이유가 경험인지, 가치관인지, 가까운 사람 때문인지 짚어봐요.', '그 주제에 대한 나만의 생각도 적어볼까요?'),
  (649, (SELECT id FROM interests WHERE code = 'VALUES'), '어떻게 죽게 될지에 대한 나만의 예감이 있나요?', 5, '무겁게 느껴질 수 있지만, 떠오르는 장면이 있다면 솔직하게 꺼내봐요.', '그 예감의 배경은 무엇일까요?', '그 생각이 지금의 삶에 어떤 영향을 주고 있는지도 적어봐요.'),
  (650, (SELECT id FROM interests WHERE code = 'VALUES'), '유명해지고 싶나요?', 3, '유명해지고 싶은 마음이 있는지, 없는지 솔직하게 떠올려봐요.', '유명해지고 싶다면 그 이유는 무엇일까요?', '어떤 방식으로 유명해지고 싶은지도 떠올려봐요.'),
  (651, (SELECT id FROM interests WHERE code = 'VALUES'), '상대의 생사와 관계 없이 아무나 한 명과 저녁을 함께할 수 있다면 누구와 저녁을 먹고 싶나요?', 3, '한 번이라도 대화를 깊게 나누고 싶은 사람이 있나요?', '그 사람을 고른 이유가 그리움인지, 궁금함인지, 존경인지 살펴봐요.', '꼭 하고 싶은 말이나 질문이 있다면 적어봐요.'),
  (652, (SELECT id FROM interests WHERE code = 'VALUES'), '인생에서 가장 감사하다고 느끼는 것은 무엇인가요?', 3, '지금까지의 삶을 하나씩 되짚어볼까요?', '어려움도 있었겠지만 감사함을 느끼는 소중한 순간도 있었을거에요.', '그중에서도 가장 감사한 마음과 일들을 떠올려봐요.'),
  (653, (SELECT id FROM interests WHERE code = 'VALUES'), '능력과 상관없이 하고 싶은 직업이 있나요?', 3, '그 직업의 어떤 매력이 내 마음을 그토록 설레게 하나요?', '그 일을 하는 나의 일상은 지금과 어떻게 달라질까요?', '현실의 제약을 벗어나고 싶은 마음이 그 직업에 투영되었나요?'),
  (654, (SELECT id FROM interests WHERE code = 'VALUES'), '인상 깊은 문장은 무엇인가요?', 3, '그 문장을 처음 만났던 장소와 시간의 분위기를 기억하나요?', '그 문장이 내 삶의 중요한 가이드라인이 되어준 적이 있나요?', '다른 사람에게도 그 문장을 꼭 추천해주고 싶은 이유가 무엇인가요?'),
  (655, (SELECT id FROM interests WHERE code = 'VALUES'), '지니를 만난다면 빌고 싶은 세 가지 소원은 무엇인가요?', 3, '지금 내 마음이 가장 간절하게 바라고 있는 건 무엇인가요?', '그 소원들이 이루어진다면 나의 매일이 더 반짝이게 될까요?', '마법 없이도 지금의 내가 스스로에게 줄 수 있는 건 없을까요?'),
  (656, (SELECT id FROM interests WHERE code = 'VALUES'), '추천하는 사람이 대통령이 된다면 누구를 뽑을 건가요?', 3, '더 나은 세상을 위해 어떤 리더가 필요하다고 생각하나요?', '그분을 선택한 마음 밑바닥에는 어떤 희망이 담겨 있나요?', '세상이 따뜻하게 변한다면 나의 하루는 어떻게 달라지나요?'),
  (657, (SELECT id FROM interests WHERE code = 'VALUES'), '이 세상에서 가장 부러운 사람은 누구인가요?', 3, '그 사람이 가진 무언가가 나의 마음을 일렁이게 하나요?', '부러움은 내가 더 빛나고 싶다는 소중한 신호일지도 몰라요.', '나도 누군가에게는 이미 충분히 멋진 사람이라는 걸 아시나요?'),
  (658, (SELECT id FROM interests WHERE code = 'VALUES'), '미신을 믿으시나요?', 3, '논리로는 설명 안 되지만 마음을 위해 지키는 습관이 있나요?', '불안을 다독이려 나만의 작은 규칙에 기대고 있지는 않나요?', '그 약속을 지켰을 때 내 마음이 한결 가벼워진다면 충분해요.'),
  (659, (SELECT id FROM interests WHERE code = 'VALUES'), '당신이 절대 할 수 없는 한 가지 일은 무엇인가요?', 4, '내 마음이 허락하지 않아 도저히 엄두가 안 나는 일이 있나요?', '그 일을 하지 않는 것이 오히려 나를 단단하게 지켜주나요?', '만약 어려운 선택 앞에 선다면 나 자신을 믿어줄 수 있나요?'),
  (660, (SELECT id FROM interests WHERE code = 'VALUES'), '인생의 마지막에 무엇을 남기고 싶나요?', 3, '시간이 흘러 내 삶이 끝날 때 사람들에게 어떤 기억으로 남고 싶나요?', '그 마지막을 생각하면 지금 고민하는 일들이 조금은 가볍게 보이나요?', '"참 괜찮은 삶이었어"라고 말하려면 오늘 무엇을 소중히 해야 할까요?');
